INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.1', 'knowledge', '{"content":"<b>Recap</b><br>• In algebra, letters represent unknown values or variables.<br>• <b>Coefficient</b>: the number in front of a variable. In $5x$, the coefficient is 5.<br>• <b>Term</b>: a number, variable, or product of both. E.g. $3x^2$, $-7y$, $4$.<br>• <b>Expression</b>: a collection of terms (no = sign). E.g. $2x + 3y - 1$.<br>• <b>Equation</b>: an expression equal to something. E.g. $2x + 3 = 11$.<br>• <b>Formula</b>: an equation relating variables. E.g. $A = \\pi r^2$.<br>• <b>Identity</b>: true for ALL values. Uses $\\equiv$. E.g. $2(x+1) \\equiv 2x + 2$.<br><br><b>Key Skills</b><br>• Substitute values into expressions and formulae.<br>• Use correct notation: $ab$ means $a \\times b$; $\\frac{a}{b}$ means $a \\div b$.<br>• Remember: $x$ means $1x$; $-x^2$ means $-(x^2)$, not $(-x)^2$.<br><br><b>Watch Out!</b><br>$-3^2 = -9$ but $(-3)^2 = 9$. Always check if the negative is inside or outside the brackets.","content_zh":"<b>知识回顾</b><br>• 代数中字母代表未知数或变量。<br>• <b>系数</b>：变量前的数字。$5x$ 中系数是 5。<br>• <b>项</b>：数字、变量或其乘积。<br>• <b>表达式</b>：项的集合（无等号）。<br>• <b>方程</b>：含等号。<b>公式</b>：关联变量的方程。<br>• <b>恒等式</b>：对所有值成立，用 $\\equiv$ 表示。<br><br><b>注意！</b><br>$-3^2 = -9$，但 $(-3)^2 = 9$。注意负号在括号内还是外。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.1', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Given $a = -2$, $b = 3$, $c = -5$, find the value of:<br>(a) $3a^2 - 2b$ &nbsp;&nbsp; (b) $\\frac{b - c}{a}$<br><br><b>Solution:</b><br>(a) $3(-2)^2 - 2(3) = 3(4) - 6 = 12 - 6 = 6$<br><br>(b) $\\frac{3 - (-5)}{-2} = \\frac{8}{-2} = -4$<br><br><b>Exam Tip:</b> Always use brackets when substituting negative numbers to avoid sign errors.","content_zh":"<b>经典例题</b> [3 分]<br>已知 $a = -2$, $b = 3$, $c = -5$，求：<br>(a) $3a^2 - 2b$ &nbsp;&nbsp; (b) $\\frac{b - c}{a}$<br><br><b>解答：</b><br>(a) $3(-2)^2 - 2(3) = 12 - 6 = 6$<br>(b) $\\frac{3-(-5)}{-2} = \\frac{8}{-2} = -4$<br><br><b>考试技巧：</b>代入负数时一定要加括号。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Rearranging</b> (changing the subject): isolate a variable on one side.<br>• Use inverse operations in reverse order of BIDMAS.<br>• Whatever you do to one side, you must do to the other.<br><br><b>Key Skills</b><br>• Rearrange simple formulae: $v = u + at$ → $t = \\frac{v - u}{a}$.<br>• Handle squares and roots: $A = \\pi r^2$ → $r = \\sqrt{\\frac{A}{\\pi}}$.<br><br><b>Extended Only</b><br>• Rearrange where the subject appears twice: collect terms, factorise, divide.<br>E.g. $\\frac{ax + b}{cx + d} = e$ → make $x$ the subject.<br><br><b>Watch Out!</b><br>When taking a square root, consider both positive and negative roots if the context requires it.","content_zh":"<b>知识回顾</b><br>• <b>变换公式</b>：将某个变量移到等号一边。<br>• 用逆运算，按 BIDMAS 逆序操作。<br>• 等号两边做相同运算。<br><br><b>Extended 扩展</b><br>• 变量出现两次时：合并同类项 → 提取公因式 → 除。<br><br><b>注意！</b><br>开方时根据情况考虑正负两个根。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.2', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Make $r$ the subject of $V = \\frac{4}{3}\\pi r^3$.<br><br><b>Solution:</b><br>$\\frac{3V}{4\\pi} = r^3$<br>$r = \\sqrt[3]{\\frac{3V}{4\\pi}}$<br><br><b>Worked Example 2</b> (Extended) [3 marks]<br>Make $x$ the subject of $y = \\frac{x + 3}{x - 1}$.<br><br><b>Solution:</b><br>$y(x - 1) = x + 3$<br>$xy - y = x + 3$<br>$xy - x = y + 3$<br>$x(y - 1) = y + 3$<br>$x = \\frac{y + 3}{y - 1}$","content_zh":"<b>经典例题 1</b> [2 分]<br>将 $V = \\frac{4}{3}\\pi r^3$ 变为以 $r$ 为主语。<br><br><b>解答：</b>$r = \\sqrt[3]{\\frac{3V}{4\\pi}}$<br><br><b>经典例题 2</b>（Extended）[3 分]<br>将 $y = \\frac{x + 3}{x - 1}$ 变为以 $x$ 为主语。<br><br><b>解答：</b><br>$y(x-1) = x+3$ → $xy - x = y+3$ → $x(y-1) = y+3$<br>$x = \\frac{y+3}{y-1}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Collect like terms</b>: $3x + 2x = 5x$; $4x^2 + x$ cannot be simplified.<br>• <b>Expand brackets</b>: $a(b + c) = ab + ac$.<br>• <b>Expand double brackets</b>: $(x + 2)(x + 3) = x^2 + 5x + 6$.<br>• <b>Factorise</b> (reverse of expanding): $6x + 9 = 3(2x + 3)$.<br><br><b>Extended Only</b><br>• <b>Factorise quadratics</b>: $x^2 + 5x + 6 = (x + 2)(x + 3)$.<br>• <b>Difference of two squares</b>: $a^2 - b^2 = (a + b)(a - b)$.<br>• <b>Perfect squares</b>: $a^2 + 2ab + b^2 = (a + b)^2$.<br>• <b>Completing the square</b>: $x^2 + bx = (x + \\frac{b}{2})^2 - (\\frac{b}{2})^2$.<br><br><b>Watch Out!</b><br>$-(x - 3) = -x + 3$, not $-x - 3$. Distribute the negative sign to ALL terms.","content_zh":"<b>知识回顾</b><br>• <b>合并同类项</b>：$3x + 2x = 5x$。<br>• <b>展开括号</b>：$a(b+c) = ab + ac$。<br>• <b>因式分解</b>：$6x + 9 = 3(2x+3)$。<br><br><b>Extended 扩展</b><br>• 二次因式分解：$x^2 + 5x + 6 = (x+2)(x+3)$。<br>• 平方差：$a^2 - b^2 = (a+b)(a-b)$。<br>• 配方：$x^2 + bx = (x + \\frac{b}{2})^2 - (\\frac{b}{2})^2$。<br><br><b>注意！</b><br>$-(x-3) = -x + 3$，负号要分配给括号内每一项。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.3', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Factorise $x^2 - 7x + 12$.<br><br><b>Solution:</b><br>Find two numbers that multiply to $+12$ and add to $-7$: $-3$ and $-4$.<br>$x^2 - 7x + 12 = (x - 3)(x - 4)$<br><br><b>Worked Example 2</b> (Extended) [3 marks]<br>Write $x^2 + 6x - 4$ in the form $(x + a)^2 + b$.<br><br><b>Solution:</b><br>$x^2 + 6x = (x + 3)^2 - 9$<br>$x^2 + 6x - 4 = (x + 3)^2 - 9 - 4 = (x + 3)^2 - 13$<br>So $a = 3$, $b = -13$.","content_zh":"<b>经典例题 1</b> [2 分]<br>因式分解 $x^2 - 7x + 12$。<br><br><b>解答：</b>找两个数乘积为 $+12$、和为 $-7$：$-3$ 和 $-4$。<br>$= (x-3)(x-4)$<br><br><b>经典例题 2</b>（Extended）[3 分]<br>将 $x^2 + 6x - 4$ 写成 $(x+a)^2 + b$ 的形式。<br><br><b>解答：</b>$(x+3)^2 - 9 - 4 = (x+3)^2 - 13$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.4', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• Algebraic fractions follow the SAME rules as numerical fractions.<br>• <b>Simplify</b>: factorise numerator and denominator, then cancel common factors.<br>• $\\frac{x^2 - 4}{x + 2} = \\frac{(x+2)(x-2)}{x+2} = x - 2$<br><br><b>Operations</b><br>• <b>Add/Subtract</b>: find a common denominator.<br>• $\\frac{2}{x} + \\frac{3}{x+1} = \\frac{2(x+1) + 3x}{x(x+1)} = \\frac{5x + 2}{x(x+1)}$<br>• <b>Multiply</b>: multiply tops and bottoms. Simplify first if possible.<br>• <b>Divide</b>: multiply by the reciprocal.<br><br><b>Watch Out!</b><br>You can only cancel FACTORS, not individual terms. $\\frac{x + 3}{x}$ does NOT simplify to $3$.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• 代数分式与数值分式规则相同。<br>• <b>化简</b>：分子分母因式分解后约分。<br>• <b>加减</b>：通分。<b>乘法</b>：分子乘分子，分母乘分母。<b>除法</b>：乘倒数。<br><br><b>注意！</b><br>只能约分因式，不能约分单独的项。$\\frac{x+3}{x} \\neq 3$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.4', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>Simplify $\\frac{3}{x-2} - \\frac{1}{x+1}$.<br><br><b>Solution:</b><br>Common denominator = $(x-2)(x+1)$<br>$= \\frac{3(x+1) - 1(x-2)}{(x-2)(x+1)}$<br>$= \\frac{3x + 3 - x + 2}{(x-2)(x+1)}$<br>$= \\frac{2x + 5}{(x-2)(x+1)}$<br><br><b>Exam Tip:</b> Be very careful with minus signs when subtracting: $-1(x - 2) = -x + 2$, not $-x - 2$.","content_zh":"<b>经典例题</b> [4 分]<br>化简 $\\frac{3}{x-2} - \\frac{1}{x+1}$。<br><br><b>解答：</b><br>通分 $(x-2)(x+1)$：<br>$= \\frac{3(x+1) - (x-2)}{(x-2)(x+1)} = \\frac{2x+5}{(x-2)(x+1)}$<br><br><b>考试技巧：</b>减法时注意负号分配：$-(x-2) = -x+2$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.5', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Linear equations</b>: $ax + b = c$. Solve by inverse operations.<br>• Equations with brackets: expand first, then solve.<br>• Equations with fractions: multiply both sides by the common denominator.<br><br><b>Extended Only</b><br>• <b>Quadratic equations</b>: $ax^2 + bx + c = 0$.<br>&nbsp;&nbsp;Method 1: <b>Factorising</b>: $(x + p)(x + q) = 0$ → $x = -p$ or $x = -q$.<br>&nbsp;&nbsp;Method 2: <b>Quadratic formula</b>: $x = \\frac{-b \\pm \\sqrt{b^2 - 4ac}}{2a}$.<br>&nbsp;&nbsp;Method 3: <b>Completing the square</b>.<br>• <b>Simultaneous equations</b>:<br>&nbsp;&nbsp;— Elimination: add/subtract to remove a variable.<br>&nbsp;&nbsp;— Substitution: express one variable in terms of the other.<br><br><b>Watch Out!</b><br>Quadratic equations have TWO solutions. Do not stop at one!","content_zh":"<b>知识回顾</b><br>• <b>一次方程</b>：$ax + b = c$，逆运算求解。<br>• 含分数的方程：两边乘以公分母。<br><br><b>Extended 扩展</b><br>• <b>二次方程</b>：$ax^2 + bx + c = 0$。<br>&nbsp;&nbsp;方法1：因式分解。方法2：求根公式 $x = \\frac{-b \\pm \\sqrt{b^2-4ac}}{2a}$。方法3：配方法。<br>• <b>联立方程</b>：消元法或代入法。<br><br><b>注意！</b><br>二次方程有两个解，不要只求一个！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.5', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Solve $\\frac{2x+1}{3} - \\frac{x-2}{4} = 2$.<br><br><b>Solution:</b><br>Multiply by 12: $4(2x+1) - 3(x-2) = 24$<br>$8x + 4 - 3x + 6 = 24$<br>$5x + 10 = 24$<br>$5x = 14$, $x = 2.8$<br><br><b>Worked Example 2</b> (Extended) [3 marks]<br>Solve $2x^2 + 5x - 3 = 0$.<br><br><b>Solution:</b><br>$(2x - 1)(x + 3) = 0$<br>$x = \\frac{1}{2}$ or $x = -3$","content_zh":"<b>经典例题 1</b> [3 分]<br>解方程 $\\frac{2x+1}{3} - \\frac{x-2}{4} = 2$。<br><br><b>解答：</b>两边乘12：$4(2x+1) - 3(x-2) = 24$<br>$5x + 10 = 24$，$x = 2.8$<br><br><b>经典例题 2</b>（Extended）[3 分]<br>解 $2x^2 + 5x - 3 = 0$。<br><br><b>解答：</b>$(2x-1)(x+3) = 0$，$x = \\frac{1}{2}$ 或 $x = -3$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.6', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Inequality symbols</b>: $<$ (less than), $>$ (greater than), $\\leq$ (less than or equal to), $\\geq$ (greater than or equal to).<br>• Solve like equations, but <b>reverse the inequality when multiplying or dividing by a negative</b>.<br>• Represent solutions on a number line: open circle ○ for $<, >$; filled circle ● for $\\leq, \\geq$.<br><br><b>Extended Only</b><br>• Solve <b>quadratic inequalities</b>: solve the equation first, then test regions.<br>• $x^2 - 4 < 0$ → $(x-2)(x+2) < 0$ → $-2 < x < 2$.<br>• Represent on a <b>graph</b>: shade the region satisfying the inequality.<br><br><b>Watch Out!</b><br>If you multiply or divide by $-1$, FLIP the inequality: $-x > 3$ becomes $x < -3$.","content_zh":"<b>知识回顾</b><br>• 不等号：$<, >, \\leq, \\geq$。<br>• 解法与方程类似，但<b>乘除负数时不等号翻转</b>。<br>• 数轴表示：空心圈 = 不包含端点，实心圈 = 包含。<br><br><b>Extended 扩展</b><br>• 二次不等式：先解方程，再判断区间。<br>• $x^2 - 4 < 0$ → $-2 < x < 2$。<br><br><b>注意！</b><br>乘除负数时不等号必须翻转！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.6', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Solve $3 - 2x \\leq 7$.<br><br><b>Solution:</b><br>$-2x \\leq 4$<br>$x \\geq -2$ (dividing by $-2$, flip the sign)<br><br><b>Worked Example 2</b> (Extended) [3 marks]<br>Solve $x^2 - 5x + 6 > 0$.<br><br><b>Solution:</b><br>$(x-2)(x-3) > 0$<br>Critical values: $x = 2$ and $x = 3$.<br>Test regions: $x < 2$ → positive ✓, $2 < x < 3$ → negative ✗, $x > 3$ → positive ✓<br>Answer: $x < 2$ or $x > 3$.","content_zh":"<b>经典例题 1</b> [2 分]<br>解 $3 - 2x \\leq 7$。<br><br><b>解答：</b>$-2x \\leq 4$，除以 $-2$ 翻转不等号：$x \\geq -2$<br><br><b>经典例题 2</b>（Extended）[3 分]<br>解 $x^2 - 5x + 6 > 0$。<br><br><b>解答：</b>$(x-2)(x-3) > 0$<br>临界值 $x = 2, 3$。测试区间得 $x < 2$ 或 $x > 3$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.7', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>sequence</b> is an ordered list of numbers following a rule.<br>• <b>Term-to-term rule</b>: describes how to get from one term to the next.<br>• <b>Position-to-term rule</b> ($n$th term): gives any term directly. E.g. $T_n = 3n + 1$.<br>• <b>Arithmetic sequence</b>: constant difference $d$. $T_n = a + (n-1)d$.<br><br><b>Extended Only</b><br>• <b>Quadratic sequences</b>: second differences are constant. $T_n = an^2 + bn + c$.<br>• Finding $a$: $a = \\frac{\\text{2nd difference}}{2}$. Then find $b$ and $c$ using known terms.<br><br><b>Exam Tip</b><br>Always check your $n$th term formula by substituting $n = 1, 2, 3$ to verify it gives the correct terms.","content_zh":"<b>知识回顾</b><br>• <b>数列</b>：按规则排列的数。<br>• <b>等差数列</b>：公差 $d$ 恒定。$T_n = a + (n-1)d$。<br><br><b>Extended 扩展</b><br>• <b>二次数列</b>：二阶差恒定。$T_n = an^2 + bn + c$。<br>• $a = \\frac{\\text{二阶差}}{2}$，再代入已知项求 $b$ 和 $c$。<br><br><b>考试技巧</b><br>用 $n = 1, 2, 3$ 代入验证通项公式。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.7', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Find the $n$th term of: $5, 8, 11, 14, ...$<br><br><b>Solution:</b><br>Common difference $d = 3$. First term $a = 5$.<br>$T_n = 3n + 2$<br>Check: $T_1 = 5$ ✓, $T_2 = 8$ ✓<br><br><b>Worked Example 2</b> (Extended) [4 marks]<br>Find the $n$th term of: $3, 9, 19, 33, 51, ...$<br><br><b>Solution:</b><br>1st differences: $6, 10, 14, 18$<br>2nd differences: $4, 4, 4$ → $a = \\frac{4}{2} = 2$<br>$T_n = 2n^2 + bn + c$<br>$n = 1$: $2 + b + c = 3$ → $b + c = 1$<br>$n = 2$: $8 + 2b + c = 9$ → $2b + c = 1$<br>Solving: $b = 0$, $c = 1$<br>$T_n = 2n^2 + 1$","content_zh":"<b>经典例题 1</b> [2 分]<br>求 $5, 8, 11, 14, ...$ 的通项。<br><br><b>解答：</b>公差 $d = 3$，$T_n = 3n + 2$<br><br><b>经典例题 2</b>（Extended）[4 分]<br>求 $3, 9, 19, 33, 51, ...$ 的通项。<br><br><b>解答：</b>二阶差 = 4，$a = 2$<br>$T_n = 2n^2 + bn + c$，代入解得 $b = 0, c = 1$<br>$T_n = 2n^2 + 1$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.8', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Direct proportion</b>: $y \\propto x$ means $y = kx$. When $x$ doubles, $y$ doubles.<br>• $y \\propto x^2$: $y = kx^2$. $y \\propto \\sqrt{x}$: $y = k\\sqrt{x}$.<br>• <b>Inverse proportion</b>: $y \\propto \\frac{1}{x}$ means $y = \\frac{k}{x}$. When $x$ doubles, $y$ halves.<br>• $y \\propto \\frac{1}{x^2}$: $y = \\frac{k}{x^2}$.<br><br><b>Method</b><br>1. Write the proportion statement.<br>2. Replace $\\propto$ with $= k$ (introduce constant).<br>3. Substitute known values to find $k$.<br>4. Write the full formula and use it.<br><br><b>Watch Out!</b><br>$y \\propto x^2$ does NOT mean $y \\propto x$ squared — they have different relationships.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• <b>正比例</b>：$y \\propto x$ → $y = kx$。<br>• $y \\propto x^2$, $y \\propto \\sqrt{x}$ 等变体。<br>• <b>反比例</b>：$y \\propto \\frac{1}{x}$ → $y = \\frac{k}{x}$。<br><br><b>方法</b><br>1. 写出比例关系。2. 用 $k$ 替换 $\\propto$。3. 代入已知值求 $k$。4. 写出完整公式。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.8', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>$y$ is inversely proportional to $x^2$. When $x = 2$, $y = 5$. Find $y$ when $x = 10$.<br><br><b>Solution:</b><br>$y = \\frac{k}{x^2}$<br>$5 = \\frac{k}{4}$ → $k = 20$<br>When $x = 10$: $y = \\frac{20}{100} = 0.2$<br><br><b>Exam Tip:</b> Always find $k$ first using the given pair of values before substituting the new value.","content_zh":"<b>经典例题</b> [4 分]<br>$y$ 与 $x^2$ 成反比。$x = 2$ 时 $y = 5$。求 $x = 10$ 时的 $y$。<br><br><b>解答：</b><br>$y = \\frac{k}{x^2}$，代入 $5 = \\frac{k}{4}$，$k = 20$<br>$x = 10$ 时：$y = \\frac{20}{100} = 0.2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.9', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Distance-time graphs</b>: gradient = speed. Horizontal line = stationary.<br>• <b>Speed-time graphs</b>: gradient = acceleration. Area under graph = distance.<br>• Steeper gradient = faster speed/greater acceleration.<br><br><b>Extended Only</b><br>• <b>Curved distance-time</b>: draw a tangent to find the speed at a given time.<br>• <b>Area under speed-time</b>: use trapezium rule for curves or split into triangles + rectangles.<br><br><b>Watch Out!</b><br>A negative gradient on a speed-time graph means deceleration, NOT going backwards.","content_zh":"<b>知识回顾</b><br>• <b>路程-时间图</b>：斜率 = 速度。水平线 = 静止。<br>• <b>速度-时间图</b>：斜率 = 加速度。图线下面积 = 路程。<br><br><b>Extended 扩展</b><br>• 曲线图：画切线求瞬时速度。<br>• 用梯形法则估算面积。<br><br><b>注意！</b><br>速度-时间图中负斜率表示减速，不是倒退。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.9', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>A speed-time graph shows: 0 to 10s accelerating uniformly from 0 to 15 m/s, then constant speed from 10s to 25s. Find the total distance.<br><br><b>Solution:</b><br>Phase 1 (triangle): $\\frac{1}{2} \\times 10 \\times 15 = 75$ m<br>Phase 2 (rectangle): $15 \\times 15 = 225$ m<br>Total = $75 + 225 = 300$ m<br><br><b>Exam Tip:</b> Split the area into simple shapes (triangles, rectangles, trapeziums).","content_zh":"<b>经典例题</b> [3 分]<br>速度-时间图：0-10秒从0均匀加速到15 m/s，10-25秒匀速。求总路程。<br><br><b>解答：</b><br>三角形面积：$\\frac{1}{2} \\times 10 \\times 15 = 75$ m<br>矩形面积：$15 \\times 15 = 225$ m<br>总路程 = $300$ m"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.10', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Linear</b>: $y = mx + c$. Straight line, gradient $m$, $y$-intercept $c$.<br>• <b>Quadratic</b>: $y = ax^2 + bx + c$. U-shape ($a > 0$) or ∩-shape ($a < 0$).<br>• <b>Cubic</b>: $y = ax^3 + ...$. S-shaped curve.<br>• <b>Reciprocal</b>: $y = \\frac{a}{x}$. Two branches in opposite quadrants.<br><br><b>Key Skills</b><br>• Complete a table of values and plot points.<br>• Draw a smooth curve through the points (not dot-to-dot straight lines).<br>• Read off solutions where curves cross the $x$-axis or each other.<br><br><b>Extended Only</b><br>• <b>Exponential</b>: $y = a^x$. Always positive, crosses $y$-axis at $(0, 1)$.<br>• <b>Trigonometric</b>: $y = \\sin x$, $y = \\cos x$, $y = \\tan x$.","content_zh":"<b>知识回顾</b><br>• <b>一次函数</b>：$y = mx + c$，直线。<br>• <b>二次函数</b>：$y = ax^2 + bx + c$，抛物线。<br>• <b>三次函数</b>：S 形曲线。<b>反比例函数</b>：$y = \\frac{a}{x}$，双曲线。<br><br><b>Extended 扩展</b><br>• <b>指数函数</b>：$y = a^x$。<br>• <b>三角函数</b>：$\\sin x, \\cos x, \\tan x$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.10', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>Draw the graph of $y = x^2 - 3x - 4$ for $-2 \\leq x \\leq 5$. Use your graph to solve $x^2 - 3x - 4 = 0$.<br><br><b>Solution:</b><br>Table of values:<br>$x$: $-2, -1, 0, 1, 2, 3, 4, 5$<br>$y$: $6, 0, -4, -6, -6, -4, 0, 6$<br><br>The graph crosses the $x$-axis at $x = -1$ and $x = 4$.<br>So $x^2 - 3x - 4 = 0$ has solutions $x = -1$ and $x = 4$.<br><br><b>Exam Tip:</b> Solutions to $y = 0$ are where the curve crosses the $x$-axis.","content_zh":"<b>经典例题</b> [4 分]<br>画 $y = x^2 - 3x - 4$ 在 $-2 \\leq x \\leq 5$ 的图像，用图解 $x^2 - 3x - 4 = 0$。<br><br><b>解答：</b>列值表，描点画曲线。<br>图像与 $x$ 轴交于 $x = -1$ 和 $x = 4$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.11', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Sketching</b> shows the general shape, key features, and approximate positions — not exact plots.<br>• Key features to show: $x$-intercepts (roots), $y$-intercept, turning points, asymptotes.<br><br><b>Key Shapes</b><br>• $y = x^2$: U-shape through origin.<br>• $y = -x^2$: ∩-shape through origin.<br>• $y = x^3$: S-curve through origin.<br>• $y = \\frac{1}{x}$: two branches, asymptotes along axes.<br>• $y = a^x$: exponential growth; $y = a^{-x}$: exponential decay.<br><br><b>Transformations</b><br>• $f(x) + a$: shift UP $a$ units.<br>• $f(x + a)$: shift LEFT $a$ units.<br>• $-f(x)$: reflect in $x$-axis.<br>• $f(-x)$: reflect in $y$-axis.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• <b>草图</b>：展示大致形状和关键特征，不需精确描点。<br>• 标出：$x$ 截距、$y$ 截距、顶点、渐近线。<br><br><b>图像变换</b><br>• $f(x) + a$：上移 $a$。$f(x+a)$：左移 $a$。<br>• $-f(x)$：关于 $x$ 轴翻转。$f(-x)$：关于 $y$ 轴翻转。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.11', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Sketch the graph of $y = (x - 2)(x + 1)(x - 4)$, showing all intercepts.<br><br><b>Solution:</b><br>$x$-intercepts: $x = 2, -1, 4$ (set each bracket = 0).<br>$y$-intercept: $y = (-2)(1)(-4) = 8$.<br>Leading term is $x^3$ (positive), so the curve goes from bottom-left to top-right.<br>The curve crosses the $x$-axis at each root.<br><br><b>Exam Tip:</b> For cubic sketches, find all $x$-intercepts and the $y$-intercept, then draw the general S-shape.","content_zh":"<b>经典例题</b> [3 分]<br>画 $y = (x-2)(x+1)(x-4)$ 的草图，标出所有截距。<br><br><b>解答：</b><br>$x$ 截距：$x = -1, 2, 4$<br>$y$ 截距：$y = (-2)(1)(-4) = 8$<br>最高次项为 $x^3$（正），曲线从左下到右上。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.12', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Differentiation</b> finds the gradient of a curve at any point.<br>• If $y = ax^n$, then $\\frac{dy}{dx} = anx^{n-1}$.<br>• For $y = x^3 + 2x^2 - 5x + 1$: $\\frac{dy}{dx} = 3x^2 + 4x - 5$.<br><br><b>Key Skills</b><br>• Find the gradient at a point: substitute $x$ into $\\frac{dy}{dx}$.<br>• Find <b>turning points</b>: set $\\frac{dy}{dx} = 0$ and solve.<br>• Determine nature: if $\\frac{d^2y}{dx^2} > 0$ → minimum; if $< 0$ → maximum.<br><br><b>Watch Out!</b><br>Constants differentiate to 0. The derivative of $5$ is $0$.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• <b>微分</b>求曲线任意点的斜率。<br>• $y = ax^n$ → $\\frac{dy}{dx} = anx^{n-1}$。<br><br><b>关键技能</b><br>• 求某点斜率：将 $x$ 代入 $\\frac{dy}{dx}$。<br>• 求<b>转折点</b>：令 $\\frac{dy}{dx} = 0$。<br>• 判断性质：$\\frac{d^2y}{dx^2} > 0$ → 最小值；$< 0$ → 最大值。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.12', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>Find the turning points of $y = 2x^3 - 9x^2 + 12x$ and determine their nature.<br><br><b>Solution:</b><br>$\\frac{dy}{dx} = 6x^2 - 18x + 12$<br>Set $= 0$: $6(x^2 - 3x + 2) = 0$<br>$6(x - 1)(x - 2) = 0$ → $x = 1$ or $x = 2$<br><br>$\\frac{d^2y}{dx^2} = 12x - 18$<br>At $x = 1$: $12(1) - 18 = -6 < 0$ → <b>maximum</b>, $y = 5$.<br>At $x = 2$: $12(2) - 18 = 6 > 0$ → <b>minimum</b>, $y = 4$.<br><br><b>Exam Tip:</b> Always find the $y$-values of turning points by substituting back into the original equation.","content_zh":"<b>经典例题</b> [5 分]<br>求 $y = 2x^3 - 9x^2 + 12x$ 的转折点并判断性质。<br><br><b>解答：</b><br>$\\frac{dy}{dx} = 6x^2 - 18x + 12 = 0$<br>$x = 1$ 或 $x = 2$<br>$\\frac{d^2y}{dx^2} = 12x - 18$<br>$x = 1$：$-6 < 0$ → 最大值，$y = 5$<br>$x = 2$：$6 > 0$ → 最小值，$y = 4$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.13', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• A <b>function</b> maps each input to exactly one output. Written as $f(x)$ or $f: x \\mapsto ...$<br>• $f(3)$ means substitute $x = 3$ into the function.<br>• <b>Composite function</b>: $fg(x) = f(g(x))$. Apply $g$ first, then $f$.<br>• <b>Inverse function</b> $f^{-1}(x)$: undoes $f$. Swap $x$ and $y$, then rearrange.<br>• The graph of $f^{-1}$ is the reflection of $f$ in the line $y = x$.<br><br><b>Key Skills</b><br>• Evaluate $f(a)$, $fg(a)$, $f^{-1}(a)$.<br>• Find composite and inverse functions algebraically.<br><br><b>Watch Out!</b><br>$fg(x) \\neq gf(x)$ in general. Order matters!","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• <b>函数</b>：每个输入对应唯一输出。$f(x)$ 或 $f: x \\mapsto ...$<br>• <b>复合函数</b>：$fg(x) = f(g(x))$，先 $g$ 后 $f$。<br>• <b>反函数</b> $f^{-1}(x)$：交换 $x, y$ 后解出 $y$。<br>• $f^{-1}$ 的图像是 $f$ 关于 $y = x$ 的对称图像。<br><br><b>注意！</b><br>$fg(x) \\neq gf(x)$，顺序很重要！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '2.13', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>$f(x) = 2x + 1$, $g(x) = x^2 - 3$.<br>(a) Find $fg(2)$. (b) Find $gf(x)$. (c) Find $f^{-1}(x)$.<br><br><b>Solution:</b><br>(a) $g(2) = 4 - 3 = 1$, $f(1) = 2(1) + 1 = 3$. So $fg(2) = 3$.<br><br>(b) $gf(x) = g(2x+1) = (2x+1)^2 - 3 = 4x^2 + 4x + 1 - 3 = 4x^2 + 4x - 2$.<br><br>(c) $y = 2x + 1$. Swap: $x = 2y + 1$. $y = \\frac{x - 1}{2}$.<br>So $f^{-1}(x) = \\frac{x - 1}{2}$.","content_zh":"<b>经典例题</b> [5 分]<br>$f(x) = 2x + 1$, $g(x) = x^2 - 3$。<br>(a) 求 $fg(2)$。(b) 求 $gf(x)$。(c) 求 $f^{-1}(x)$。<br><br><b>解答：</b><br>(a) $g(2) = 1$, $f(1) = 3$。$fg(2) = 3$。<br>(b) $gf(x) = (2x+1)^2 - 3 = 4x^2 + 4x - 2$。<br>(c) $f^{-1}(x) = \\frac{x-1}{2}$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.1', 'knowledge', '{"content":"<b>Recap</b><br>• Letters represent unknowns or variables.<br>• <b>Expression</b>: no equals sign. E.g. $3x + 2y$.<br>• <b>Equation</b>: has an equals sign. E.g. $3x + 2 = 11$.<br>• <b>Formula</b>: relates variables. E.g. $s = \\frac{d}{t}$.<br>• <b>Identity</b>: true for all values. E.g. $3(x + 1) \\equiv 3x + 3$.<br><br><b>Key Skills</b><br>• Substitute values into expressions and formulae.<br>• Write expressions from word problems.<br>• Distinguish between expressions, equations, formulae, and identities.","content_zh":"<b>知识回顾</b><br>• 字母代表未知数或变量。<br>• <b>表达式</b>：无等号。<b>方程</b>：有等号。<br>• <b>公式</b>：变量间的关系。<b>恒等式</b>：对所有值成立。<br><br><b>关键技能</b><br>• 代入求值。从文字题写出表达式。区分四种代数形式。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.1', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>$P = 2(l + w)$. Find $P$ when $l = 8.5$ and $w = 3.2$.<br><br><b>Solution:</b><br>$P = 2(8.5 + 3.2) = 2(11.7) = 23.4$<br><br><b>Exam Tip:</b> Always show the substitution step — do not jump straight to the answer.","content_zh":"<b>经典例题</b> [3 分]<br>$P = 2(l + w)$，$l = 8.5$，$w = 3.2$ 时求 $P$。<br><br><b>解答：</b>$P = 2(8.5 + 3.2) = 23.4$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Collect like terms</b>: $5a + 3a = 8a$, but $5a + 3b$ cannot be simplified.<br>• <b>Expand single brackets</b>: $3(2x - 5) = 6x - 15$.<br>• <b>Expand double brackets</b>: $(x + 3)(x - 2) = x^2 + x - 6$.<br>• <b>Factorise</b>: take out common factors. $12x^2 + 8x = 4x(3x + 2)$.<br><br><b>Higher Only</b><br>• Factorise quadratics: $x^2 + 5x + 6 = (x + 2)(x + 3)$.<br>• Difference of two squares: $x^2 - 49 = (x + 7)(x - 7)$.<br>• <b>Algebraic fractions</b>: simplify, add, subtract using common denominators.<br><br><b>Watch Out!</b><br>$(x + 3)^2 = x^2 + 6x + 9$, NOT $x^2 + 9$. Do not forget the middle term!","content_zh":"<b>知识回顾</b><br>• 合并同类项、展开括号、因式分解。<br><br><b>仅 Higher</b><br>• 二次因式分解、平方差、代数分式运算。<br><br><b>注意！</b><br>$(x+3)^2 = x^2 + 6x + 9$，不是 $x^2 + 9$，别漏中间项！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.2', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Expand and simplify $(3x - 2)(x + 5)$.<br><br><b>Solution:</b><br>$= 3x^2 + 15x - 2x - 10 = 3x^2 + 13x - 10$<br><br><b>Worked Example 2</b> (Higher) [2 marks]<br>Factorise $6x^2 - 7x - 3$.<br><br><b>Solution:</b><br>Find two numbers: product = $6 \\times (-3) = -18$, sum = $-7$: that''s $-9$ and $2$.<br>$6x^2 - 9x + 2x - 3 = 3x(2x - 3) + 1(2x - 3) = (3x + 1)(2x - 3)$","content_zh":"<b>经典例题 1</b> [2 分]<br>展开 $(3x-2)(x+5)$。<br><br><b>解答：</b>$= 3x^2 + 13x - 10$<br><br><b>经典例题 2</b>（Higher）[2 分]<br>因式分解 $6x^2 - 7x - 3$。<br><br><b>解答：</b>$(3x+1)(2x-3)$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Substitution</b>: replace letters with numbers and evaluate.<br>• <b>Rearranging formulae</b>: change the subject using inverse operations.<br>• E.g. $v = u + at$ → $t = \\frac{v - u}{a}$.<br><br><b>Higher Only</b><br>• Rearrange with the subject appearing <b>twice</b>: collect, factorise, divide.<br>• E.g. $T = \\frac{ax}{x + b}$ → make $x$ the subject.<br><br><b>Exam Tip</b><br>When rearranging, do inverse operations in reverse BIDMAS order: undo add/subtract first, then multiply/divide, then powers/roots.","content_zh":"<b>知识回顾</b><br>• <b>代入</b>：用数值替换字母。<br>• <b>变换公式</b>：用逆运算改变主语。<br><br><b>仅 Higher</b><br>• 变量出现两次时：合并 → 提公因式 → 除。<br><br><b>考试技巧</b><br>按逆 BIDMAS 顺序操作：先解加减，再解乘除，最后解幂/根。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.3', 'examples', '{"content":"<b>Worked Example</b> (Higher) [3 marks]<br>Make $x$ the subject of $y = \\frac{3x + 2}{x - 1}$.<br><br><b>Solution:</b><br>$y(x - 1) = 3x + 2$<br>$xy - y = 3x + 2$<br>$xy - 3x = y + 2$<br>$x(y - 3) = y + 2$<br>$x = \\frac{y + 2}{y - 3}$<br><br><b>Exam Tip:</b> Get all terms with $x$ on one side, everything else on the other, then factorise out $x$.","content_zh":"<b>经典例题</b>（Higher）[3 分]<br>将 $y = \\frac{3x+2}{x-1}$ 变为以 $x$ 为主语。<br><br><b>解答：</b><br>$xy - y = 3x + 2$ → $xy - 3x = y + 2$ → $x(y-3) = y+2$<br>$x = \\frac{y+2}{y-3}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.4', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Linear equations</b> have the variable to the power 1 only.<br>• Solve by doing the same operation to both sides.<br>• Equations with brackets: expand first.<br>• Equations with fractions: multiply by the common denominator.<br>• Variables on both sides: collect variable terms on one side, numbers on the other.<br><br><b>Key Skills</b><br>• Solve $ax + b = c$, $a(x + b) = c$, $\\frac{ax + b}{c} = d$.<br>• Set up and solve equations from word problems.<br><br><b>Exam Tip</b><br>Always check your answer by substituting it back into the original equation.","content_zh":"<b>知识回顾</b><br>• <b>一次方程</b>：变量幂次为 1。两边做相同运算求解。<br>• 含括号：先展开。含分数：先通分。<br>• 变量在两边：变量移一边，数字移另一边。<br><br><b>考试技巧</b><br>把答案代回原方程检验。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.4', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Solve $\\frac{5x - 3}{4} = \\frac{x + 2}{3}$.<br><br><b>Solution:</b><br>Multiply by 12: $3(5x - 3) = 4(x + 2)$<br>$15x - 9 = 4x + 8$<br>$11x = 17$<br>$x = \\frac{17}{11}$<br><br><b>Exam Tip:</b> Cross-multiply or find the LCM of the denominators.","content_zh":"<b>经典例题</b> [3 分]<br>解 $\\frac{5x-3}{4} = \\frac{x+2}{3}$。<br><br><b>解答：</b>两边乘12：$3(5x-3) = 4(x+2)$<br>$11x = 17$，$x = \\frac{17}{11}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.5', 'knowledge', '{"content":"<b>Higher Only</b><br><br><b>Recap</b><br>• $y \\propto x$ → $y = kx$ (direct proportion).<br>• $y \\propto x^2$ → $y = kx^2$. $y \\propto x^3$ → $y = kx^3$.<br>• $y \\propto \\frac{1}{x}$ → $y = \\frac{k}{x}$ (inverse proportion).<br>• $y \\propto \\frac{1}{x^2}$ → $y = \\frac{k}{x^2}$.<br><br><b>Method</b><br>1. Write the proportionality statement.<br>2. Replace $\\propto$ with $= k$.<br>3. Substitute to find $k$.<br>4. Write the complete equation and use it.<br><br><b>Exam Tip</b><br>Read the question carefully: \"directly proportional to the square of $x$\" means $y \\propto x^2$, not $y \\propto x$.","content_zh":"<b>仅 Higher</b><br><br><b>知识回顾</b><br>• 正比例：$y = kx$, $y = kx^2$ 等。反比例：$y = \\frac{k}{x}$, $y = \\frac{k}{x^2}$。<br><br><b>方法</b><br>1. 写出比例关系。2. 用 $k$ 替换 $\\propto$。3. 代入求 $k$。4. 用公式求解。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.5', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>$y$ is directly proportional to $\\sqrt{x}$. When $x = 16$, $y = 10$. Find $y$ when $x = 25$.<br><br><b>Solution:</b><br>$y = k\\sqrt{x}$<br>$10 = k\\sqrt{16} = 4k$ → $k = 2.5$<br>When $x = 25$: $y = 2.5 \\times \\sqrt{25} = 2.5 \\times 5 = 12.5$<br><br><b>Exam Tip:</b> Always state the equation with $k$ found before substituting the new value.","content_zh":"<b>经典例题</b> [4 分]<br>$y$ 与 $\\sqrt{x}$ 成正比。$x = 16$ 时 $y = 10$。求 $x = 25$ 时 $y$。<br><br><b>解答：</b>$y = k\\sqrt{x}$，$10 = 4k$，$k = 2.5$<br>$x = 25$：$y = 2.5 \\times 5 = 12.5$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.6', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Simultaneous equations</b> are two equations with two unknowns.<br>• <b>Elimination method</b>: make coefficients of one variable equal, then add/subtract.<br>• <b>Substitution method</b>: express one variable in terms of the other, then substitute.<br><br><b>Higher Only</b><br>• Solve one linear and one non-linear (e.g. one quadratic): use substitution.<br>• E.g. $y = 2x + 1$ and $x^2 + y^2 = 25$: substitute $y$ into the second equation.<br><br><b>Exam Tip</b><br>After finding one variable, substitute back to find the other. Always find BOTH values.","content_zh":"<b>知识回顾</b><br>• <b>联立方程</b>：两个方程两个未知数。<br>• <b>消元法</b>：使一个变量系数相同，加减消去。<br>• <b>代入法</b>：用一个变量表示另一个，代入。<br><br><b>仅 Higher</b><br>• 一个一次方程 + 一个非线性方程：用代入法。<br><br><b>考试技巧</b><br>求出一个变量后代回求另一个，两个值都要求！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.6', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Solve: $3x + 2y = 16$ and $5x - 2y = 24$.<br><br><b>Solution:</b><br>Add: $8x = 40$ → $x = 5$<br>Substitute: $15 + 2y = 16$ → $2y = 1$ → $y = 0.5$<br><br><b>Worked Example 2</b> (Higher) [5 marks]<br>Solve: $y = x + 3$ and $x^2 + y^2 = 29$.<br><br><b>Solution:</b><br>$x^2 + (x+3)^2 = 29$<br>$x^2 + x^2 + 6x + 9 = 29$<br>$2x^2 + 6x - 20 = 0$ → $x^2 + 3x - 10 = 0$<br>$(x + 5)(x - 2) = 0$ → $x = -5$ or $x = 2$<br>$y = -2$ or $y = 5$","content_zh":"<b>经典例题 1</b> [3 分]<br>解：$3x + 2y = 16$，$5x - 2y = 24$。<br><br><b>解答：</b>相加：$8x = 40$，$x = 5$，$y = 0.5$<br><br><b>经典例题 2</b>（Higher）[5 分]<br>解：$y = x+3$ 和 $x^2 + y^2 = 29$。<br><br><b>解答：</b>代入得 $2x^2 + 6x - 20 = 0$<br>$x = -5, y = -2$ 或 $x = 2, y = 5$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.7', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>quadratic equation</b> has the form $ax^2 + bx + c = 0$.<br>• <b>Factorising</b>: $(x + p)(x + q) = 0$ → $x = -p$ or $x = -q$.<br><br><b>Higher Only</b><br>• <b>Quadratic formula</b>: $x = \\frac{-b \\pm \\sqrt{b^2 - 4ac}}{2a}$.<br>• <b>Completing the square</b>: $x^2 + bx + c = (x + \\frac{b}{2})^2 - (\\frac{b}{2})^2 + c$.<br>• <b>Discriminant</b> $D = b^2 - 4ac$:<br>&nbsp;&nbsp;$D > 0$: two distinct real roots.<br>&nbsp;&nbsp;$D = 0$: one repeated root.<br>&nbsp;&nbsp;$D < 0$: no real roots.<br><br><b>Watch Out!</b><br>The equation must be in the form $= 0$ before factorising or using the formula.","content_zh":"<b>知识回顾</b><br>• 二次方程：$ax^2 + bx + c = 0$。<br>• 因式分解法求解。<br><br><b>仅 Higher</b><br>• 求根公式：$x = \\frac{-b \\pm \\sqrt{b^2-4ac}}{2a}$。<br>• 配方法。<br>• 判别式 $D = b^2 - 4ac$：$D > 0$ 两个实根，$D = 0$ 一个重根，$D < 0$ 无实根。<br><br><b>注意！</b><br>使用公式前方程必须等于 0。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.7', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Solve $x^2 - 8x + 15 = 0$.<br><br><b>Solution:</b><br>$(x - 3)(x - 5) = 0$ → $x = 3$ or $x = 5$<br><br><b>Worked Example 2</b> (Higher) [3 marks]<br>Solve $3x^2 + 2x - 4 = 0$. Give your answers to 2 d.p.<br><br><b>Solution:</b><br>$x = \\frac{-2 \\pm \\sqrt{4 + 48}}{6} = \\frac{-2 \\pm \\sqrt{52}}{6}$<br>$x = \\frac{-2 + 7.211...}{6} = 0.87$ or $x = \\frac{-2 - 7.211...}{6} = -1.54$<br><br><b>Exam Tip:</b> When using the formula, calculate the discriminant first, then the two values of $x$ separately.","content_zh":"<b>经典例题 1</b> [3 分]<br>解 $x^2 - 8x + 15 = 0$。<br><br><b>解答：</b>$(x-3)(x-5) = 0$，$x = 3$ 或 $x = 5$<br><br><b>经典例题 2</b>（Higher）[3 分]<br>解 $3x^2 + 2x - 4 = 0$（保留 2 位小数）。<br><br><b>解答：</b>$x = \\frac{-2 \\pm \\sqrt{52}}{6}$<br>$x = 0.87$ 或 $x = -1.54$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.8', 'knowledge', '{"content":"<b>Recap</b><br>• $<$ less than, $>$ greater than, $\\leq$ less than or equal, $\\geq$ greater than or equal.<br>• Solve like equations. <b>Flip the sign when multiplying/dividing by negative.</b><br>• Number line: open circle (○) for strict inequalities, filled (●) for $\\leq, \\geq$.<br>• List integer values that satisfy an inequality.<br><br><b>Higher Only</b><br>• <b>Quadratic inequalities</b>: solve the equation, then determine which regions satisfy the inequality.<br>• <b>Graphical inequalities</b>: shade regions, use solid line for $\\leq/\\geq$, dashed for $</>$.<br><br><b>Exam Tip</b><br>For \"list the integers\" questions, remember to include endpoints if the inequality allows (≤ or ≥).","content_zh":"<b>知识回顾</b><br>• 不等号：$<, >, \\leq, \\geq$。<br>• 解法同方程，乘除负数翻转不等号。<br>• 数轴：空心圈 = 不含端点，实心圈 = 含端点。<br><br><b>仅 Higher</b><br>• 二次不等式：先解方程，再判断区间。<br>• 图形不等式：实线表示 $\\leq/\\geq$，虚线表示 $</>$。<br><br><b>考试技巧</b><br>\"列出满足条件的整数\"时注意是否包含端点。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '2.8', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Solve $-3 < 2x + 1 \\leq 9$. List the integer values of $x$.<br><br><b>Solution:</b><br>$-3 < 2x + 1 \\leq 9$<br>$-4 < 2x \\leq 8$<br>$-2 < x \\leq 4$<br>Integer values: $-1, 0, 1, 2, 3, 4$<br><br><b>Worked Example 2</b> (Higher) [3 marks]<br>Solve $x^2 - 3x - 10 \\leq 0$.<br><br><b>Solution:</b><br>$(x - 5)(x + 2) \\leq 0$<br>Roots: $x = 5$ and $x = -2$.<br>The quadratic is ≤ 0 between the roots: $-2 \\leq x \\leq 5$.","content_zh":"<b>经典例题 1</b> [2 分]<br>解 $-3 < 2x + 1 \\leq 9$，列出整数值。<br><br><b>解答：</b>$-2 < x \\leq 4$<br>整数：$-1, 0, 1, 2, 3, 4$<br><br><b>经典例题 2</b>（Higher）[3 分]<br>解 $x^2 - 3x - 10 \\leq 0$。<br><br><b>解答：</b>$(x-5)(x+2) \\leq 0$<br>根之间：$-2 \\leq x \\leq 5$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.1', 'knowledge', '{"content":"<b>Recap</b><br>• The <b>Cartesian plane</b> has a horizontal $x$-axis and vertical $y$-axis, crossing at the <b>origin</b> $(0, 0)$.<br>• A point is written as $(x, y)$. The $x$-coordinate comes first.<br>• <b>Four quadrants</b>: Q1 $(+, +)$, Q2 $(-, +)$, Q3 $(-, -)$, Q4 $(+, -)$.<br><br><b>Key Skills</b><br>• Plot and read coordinates in all four quadrants.<br>• Identify coordinates from geometric shapes drawn on axes.","content_zh":"<b>知识回顾</b><br>• <b>笛卡尔平面</b>：水平 $x$ 轴和垂直 $y$ 轴，交于<b>原点</b> $(0,0)$。<br>• 点写作 $(x, y)$，$x$ 坐标在前。<br>• 四个象限：Q1 $(+,+)$, Q2 $(-,+)$, Q3 $(-,-)$, Q4 $(+,-)$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.1', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>A rectangle has vertices at $A(1, 2)$, $B(5, 2)$, $C(5, 6)$. Find $D$.<br><br><b>Solution:</b><br>$D$ must complete the rectangle: same $x$ as $A$, same $y$ as $C$.<br>$D = (1, 6)$<br><br><b>Exam Tip:</b> Sketch the shape on axes to visualise the missing vertex.","content_zh":"<b>经典例题</b> [2 分]<br>矩形顶点 $A(1,2)$, $B(5,2)$, $C(5,6)$，求 $D$。<br><br><b>解答：</b>$D = (1, 6)$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.2', 'knowledge', '{"content":"<b>Recap</b><br>• A linear graph is a straight line. Equation: $y = mx + c$.<br>• To draw: make a table of at least 3 values of $(x, y)$, plot, and join with a ruler.<br>• Special lines: $y = c$ is horizontal; $x = a$ is vertical.<br><br><b>Key Skills</b><br>• Draw lines from equations. Read equations from graphs.<br>• Find where two lines intersect (solve simultaneously).<br><br><b>Exam Tip</b><br>Use 3 points to draw a line — the third point checks for errors.","content_zh":"<b>知识回顾</b><br>• 一次函数图像是直线。$y = mx + c$。<br>• 画法：列表求至少3个点，描点连线。<br>• 特殊线：$y = c$ 水平；$x = a$ 垂直。<br><br><b>考试技巧</b><br>用3个点画线，第3个点用于检验。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.2', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Draw the graph of $y = 2x - 3$ for $-1 \\leq x \\leq 4$.<br><br><b>Solution:</b><br>$x = -1$: $y = -5$; $x = 0$: $y = -3$; $x = 2$: $y = 1$; $x = 4$: $y = 5$.<br>Plot these points and join with a straight line.<br><br><b>Exam Tip:</b> Always use a ruler for straight-line graphs.","content_zh":"<b>经典例题</b> [3 分]<br>画 $y = 2x - 3$ 在 $-1 \\leq x \\leq 4$ 的图像。<br><br><b>解答：</b>代入 $x = -1, 0, 2, 4$ 得 $y = -5, -3, 1, 5$，描点用直尺连线。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Gradient</b> (slope) = $\\frac{\\text{rise}}{\\text{run}} = \\frac{y_2 - y_1}{x_2 - x_1}$.<br>• Positive gradient: line goes uphill (left to right).<br>• Negative gradient: line goes downhill.<br>• Zero gradient: horizontal line. Undefined gradient: vertical line.<br>• In $y = mx + c$, $m$ is the gradient.<br><br><b>Key Skills</b><br>• Calculate gradient from two points.<br>• Read gradient from a graph using a right-angled triangle.<br><br><b>Exam Tip</b><br>Pick two points far apart on the line for a more accurate gradient calculation.","content_zh":"<b>知识回顾</b><br>• <b>斜率</b> = $\\frac{y_2 - y_1}{x_2 - x_1}$。<br>• 正斜率：上升。负斜率：下降。零斜率：水平。未定义：垂直。<br>• $y = mx + c$ 中 $m$ 为斜率。<br><br><b>考试技巧</b><br>选距离较远的两点计算斜率更准确。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.3', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>Find the gradient of the line through $(2, 5)$ and $(8, -1)$.<br><br><b>Solution:</b><br>$m = \\frac{-1 - 5}{8 - 2} = \\frac{-6}{6} = -1$<br><br><b>Exam Tip:</b> Be consistent: always subtract in the same order for both coordinates.","content_zh":"<b>经典例题</b> [2 分]<br>求过 $(2,5)$ 和 $(8,-1)$ 的直线斜率。<br><br><b>解答：</b>$m = \\frac{-1-5}{8-2} = -1$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.4', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Distance</b> between $(x_1, y_1)$ and $(x_2, y_2)$:<br>$d = \\sqrt{(x_2 - x_1)^2 + (y_2 - y_1)^2}$ (Pythagoras on the coordinate plane).<br>• <b>Midpoint</b>: $M = \\left(\\frac{x_1 + x_2}{2}, \\frac{y_1 + y_2}{2}\\right)$.<br><br><b>Key Skills</b><br>• Calculate the exact distance between two points.<br>• Find the midpoint of a line segment.<br><br><b>Exam Tip</b><br>Leave answers in surd form if the question says \"exact value\".","content_zh":"<b>知识回顾</b><br>• <b>两点距离</b>：$d = \\sqrt{(x_2-x_1)^2 + (y_2-y_1)^2}$。<br>• <b>中点</b>：$M = \\left(\\frac{x_1+x_2}{2}, \\frac{y_1+y_2}{2}\\right)$。<br><br><b>考试技巧</b><br>题目要求\"精确值\"时用根式表示。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.4', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Find the distance and midpoint of $A(1, 3)$ and $B(7, 11)$.<br><br><b>Solution:</b><br>$d = \\sqrt{(7-1)^2 + (11-3)^2} = \\sqrt{36 + 64} = \\sqrt{100} = 10$<br>$M = \\left(\\frac{1+7}{2}, \\frac{3+11}{2}\\right) = (4, 7)$","content_zh":"<b>经典例题</b> [3 分]<br>求 $A(1,3)$ 和 $B(7,11)$ 的距离和中点。<br><br><b>解答：</b>$d = \\sqrt{36+64} = 10$，$M = (4, 7)$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.5', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Slope-intercept form</b>: $y = mx + c$ (gradient $m$, $y$-intercept $c$).<br>• Given gradient and a point: $y - y_1 = m(x - x_1)$.<br>• Given two points: find $m$ first, then use point-slope form.<br><br><b>Key Skills</b><br>• Write the equation of a line from a graph.<br>• Write the equation from gradient + point, or two points.<br>• Rearrange between $y = mx + c$ and $ax + by = c$.<br><br><b>Exam Tip</b><br>If given a graph, read off the $y$-intercept and calculate the gradient to write $y = mx + c$.","content_zh":"<b>知识回顾</b><br>• $y = mx + c$：斜率 $m$，$y$ 截距 $c$。<br>• 已知斜率和一点：$y - y_1 = m(x - x_1)$。<br>• 已知两点：先求 $m$，再用点斜式。<br><br><b>考试技巧</b><br>从图中读出 $y$ 截距和斜率即可写出方程。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.5', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Find the equation of the line through $(2, 1)$ and $(6, 9)$.<br><br><b>Solution:</b><br>$m = \\frac{9-1}{6-2} = \\frac{8}{4} = 2$<br>$y - 1 = 2(x - 2)$<br>$y = 2x - 3$","content_zh":"<b>经典例题</b> [3 分]<br>求过 $(2,1)$ 和 $(6,9)$ 的直线方程。<br><br><b>解答：</b>$m = 2$，$y - 1 = 2(x-2)$，$y = 2x - 3$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.6', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Parallel lines</b> have the SAME gradient.<br>• If $L_1$ has gradient $m$, any line parallel to it also has gradient $m$.<br>• To find a parallel line through a given point: use $y - y_1 = m(x - x_1)$ with the same $m$.<br><br><b>Exam Tip</b><br>When asked \"find the equation of the line parallel to $y = 3x + 1$ through $(2, 5)$\", the gradient is 3.","content_zh":"<b>知识回顾</b><br>• <b>平行线</b>斜率相同。<br>• 求过某点的平行线：用相同斜率 $m$ 代入点斜式。<br><br><b>考试技巧</b><br>\"平行于 $y = 3x+1$\" → 斜率为 3。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.6', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>Find the equation of the line parallel to $y = -2x + 5$ that passes through $(3, 1)$.<br><br><b>Solution:</b><br>Gradient $m = -2$ (same as the given line).<br>$y - 1 = -2(x - 3)$<br>$y = -2x + 7$","content_zh":"<b>经典例题</b> [2 分]<br>求平行于 $y = -2x+5$、过 $(3,1)$ 的直线方程。<br><br><b>解答：</b>$m = -2$，$y - 1 = -2(x-3)$，$y = -2x + 7$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.7', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Perpendicular lines</b> meet at 90°.<br>• If one line has gradient $m$, a perpendicular line has gradient $-\\frac{1}{m}$.<br>• Product of gradients of perpendicular lines = $-1$: $m_1 \\times m_2 = -1$.<br><br><b>Key Skills</b><br>• Find the gradient of a perpendicular line.<br>• Write the equation of a perpendicular through a given point.<br>• Find the perpendicular bisector of a line segment (passes through midpoint, perpendicular gradient).<br><br><b>Watch Out!</b><br>The negative reciprocal of $\\frac{2}{3}$ is $-\\frac{3}{2}$, not $-\\frac{2}{3}$.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• <b>垂直线</b>成 90°。<br>• 斜率 $m$ 的垂直线斜率为 $-\\frac{1}{m}$。<br>• 垂直线斜率之积 = $-1$。<br>• <b>垂直平分线</b>：过中点且斜率为负倒数。<br><br><b>注意！</b><br>$\\frac{2}{3}$ 的负倒数是 $-\\frac{3}{2}$，不是 $-\\frac{2}{3}$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '3.7', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Line $L$ passes through $A(1, 4)$ and $B(5, 2)$. Find the equation of the perpendicular bisector of $AB$.<br><br><b>Solution:</b><br>Midpoint: $M = (3, 3)$<br>Gradient of $AB$: $m = \\frac{2-4}{5-1} = -\\frac{1}{2}$<br>Perpendicular gradient: $m_{\\perp} = 2$<br>$y - 3 = 2(x - 3)$<br>$y = 2x - 3$<br><br><b>Exam Tip:</b> Perpendicular bisector = midpoint + negative reciprocal gradient.","content_zh":"<b>经典例题</b> [3 分]<br>直线 $L$ 过 $A(1,4)$ 和 $B(5,2)$，求 $AB$ 的垂直平分线方程。<br><br><b>解答：</b>中点 $(3,3)$，$AB$ 斜率 $-\\frac{1}{2}$，垂直斜率 $2$<br>$y - 3 = 2(x-3)$，$y = 2x - 3$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.1', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>sequence</b> is an ordered list of numbers following a pattern.<br>• <b>Term-to-term rule</b>: how to get from one term to the next.<br>• <b>$n$th term</b> (position-to-term): $T_n$ gives any term directly.<br>• <b>Arithmetic</b>: constant difference $d$. $T_n = a + (n-1)d$ or $T_n = dn + (a - d)$.<br><br><b>Higher Only</b><br>• <b>Quadratic sequences</b>: second differences are constant. $T_n = an^2 + bn + c$.<br>• <b>Geometric sequences</b>: constant ratio $r$. $T_n = ar^{n-1}$.<br>• <b>Fibonacci-type</b>: each term = sum of previous two.<br><br><b>Exam Tip</b><br>Always check your formula with $n = 1, 2, 3$.","content_zh":"<b>知识回顾</b><br>• <b>等差数列</b>：公差 $d$ 恒定，$T_n = dn + (a-d)$。<br><br><b>仅 Higher</b><br>• <b>二次数列</b>：二阶差恒定，$T_n = an^2 + bn + c$。<br>• <b>等比数列</b>：公比 $r$，$T_n = ar^{n-1}$。<br><br><b>考试技巧</b><br>用 $n = 1, 2, 3$ 代入检验公式。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Find the $n$th term of $7, 11, 15, 19, ...$<br><br><b>Solution:</b><br>$d = 4$, $T_n = 4n + 3$. Check: $T_1 = 7$ ✓<br><br><b>Worked Example 2</b> (Higher) [4 marks]<br>Find the $n$th term of $2, 8, 18, 32, 50, ...$<br><br><b>Solution:</b><br>1st diff: $6, 10, 14, 18$. 2nd diff: $4, 4, 4$ → $a = 2$.<br>$T_n = 2n^2 + bn + c$.<br>$n = 1$: $2 + b + c = 2$ → $b + c = 0$.<br>$n = 2$: $8 + 2b + c = 8$ → $2b + c = 0$.<br>$b = 0, c = 0$. $T_n = 2n^2$.","content_zh":"<b>经典例题 1</b> [2 分]<br>求 $7, 11, 15, 19, ...$ 的通项。<br><br><b>解答：</b>$d = 4$，$T_n = 4n + 3$<br><br><b>经典例题 2</b>（Higher）[4 分]<br>求 $2, 8, 18, 32, 50, ...$ 的通项。<br><br><b>解答：</b>二阶差 = 4，$a = 2$，解得 $T_n = 2n^2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.2', 'knowledge', '{"content":"<b>Higher Only</b><br><br><b>Recap</b><br>• <b>Function notation</b>: $f(x) = 2x + 3$ means \"the function $f$ maps $x$ to $2x + 3$\".<br>• $f(5) = 2(5) + 3 = 13$.<br>• <b>Composite functions</b>: $fg(x) = f(g(x))$. Do $g$ first, then $f$.<br>• <b>Inverse functions</b>: $f^{-1}(x)$ undoes $f$. Swap $x$ and $y$, then rearrange.<br>• $ff^{-1}(x) = f^{-1}f(x) = x$.<br>• The graph of $f^{-1}$ is the reflection of $f$ in $y = x$.<br><br><b>Watch Out!</b><br>$fg(x) \\neq gf(x)$ — composition is NOT commutative.","content_zh":"<b>仅 Higher</b><br><br><b>知识回顾</b><br>• 函数符号：$f(x) = 2x + 3$。<br>• 复合函数：$fg(x) = f(g(x))$，先 $g$ 后 $f$。<br>• 反函数：$f^{-1}(x)$，交换 $x, y$ 后解出。<br>• $f^{-1}$ 图像是 $f$ 关于 $y = x$ 的对称。<br><br><b>注意！</b>$fg(x) \\neq gf(x)$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.2', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>$f(x) = 3x - 1$, $g(x) = x^2 + 4$.<br>(a) Find $gf(2)$. (b) Find $fg(x)$. (c) Find $f^{-1}(x)$.<br><br><b>Solution:</b><br>(a) $f(2) = 5$, $g(5) = 29$. So $gf(2) = 29$.<br>(b) $fg(x) = f(x^2 + 4) = 3(x^2 + 4) - 1 = 3x^2 + 11$.<br>(c) $y = 3x - 1$ → $x = 3y - 1$ → $y = \\frac{x + 1}{3}$.<br>$f^{-1}(x) = \\frac{x + 1}{3}$.","content_zh":"<b>经典例题</b> [5 分]<br>$f(x) = 3x-1$, $g(x) = x^2+4$。<br>(a) $gf(2)$ (b) $fg(x)$ (c) $f^{-1}(x)$<br><br><b>解答：</b>(a) $f(2)=5, g(5)=29$<br>(b) $3x^2 + 11$<br>(c) $f^{-1}(x) = \\frac{x+1}{3}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Linear</b>: $y = mx + c$. Straight line.<br>• <b>Quadratic</b>: $y = ax^2 + bx + c$. Parabola.<br>• <b>Cubic</b>: $y = ax^3 + ...$. S-shaped.<br>• <b>Reciprocal</b>: $y = \\frac{a}{x}$. Hyperbola with asymptotes along axes.<br><br><b>Key Skills</b><br>• Plot graphs from tables of values.<br>• Find solutions graphically (intersections with $x$-axis or other curves).<br>• Read off and interpret gradients, intercepts, and turning points.<br><br><b>Higher Only</b><br>• <b>Exponential</b>: $y = a^x$ (growth), $y = a^{-x}$ (decay).<br>• <b>Trig graphs</b>: $\\sin x$, $\\cos x$, $\\tan x$ with period and amplitude.<br>• <b>Transformations</b>: $f(x) + a$ (up), $f(x + a)$ (left), $af(x)$ (vertical stretch), $f(ax)$ (horizontal compress).<br>• <b>Tangent to a curve</b>: draw tangent, calculate gradient.","content_zh":"<b>知识回顾</b><br>• 一次、二次、三次、反比例函数图像。<br><br><b>仅 Higher</b><br>• 指数函数、三角函数图像。<br>• 图像变换：$f(x)+a$ 上移，$f(x+a)$ 左移，$af(x)$ 纵向拉伸，$f(ax)$ 横向压缩。<br>• 画切线求斜率。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.3', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>The graph of $y = f(x)$ has a maximum at $(2, 5)$. Write down the coordinates of the maximum of:<br>(a) $y = f(x) + 3$ &nbsp;&nbsp; (b) $y = f(x - 4)$ &nbsp;&nbsp; (c) $y = -f(x)$<br><br><b>Solution:</b><br>(a) Shift up 3: $(2, 8)$<br>(b) Shift right 4: $(6, 5)$<br>(c) Reflect in $x$-axis: $(2, -5)$ — this becomes a <b>minimum</b>.<br><br><b>Exam Tip:</b> $f(x - a)$ shifts RIGHT, $f(x + a)$ shifts LEFT. The sign is opposite to what you might expect.","content_zh":"<b>经典例题</b> [4 分]<br>$y = f(x)$ 最大值在 $(2,5)$，求下列函数最大值坐标：<br>(a) $y = f(x)+3$ (b) $y = f(x-4)$ (c) $y = -f(x)$<br><br><b>解答：</b>(a) $(2, 8)$<br>(b) $(6, 5)$<br>(c) $(2, -5)$（变为最小值）"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.4', 'knowledge', '{"content":"<b>Higher Only</b><br><br><b>Recap</b><br>• <b>Differentiation</b>: if $y = ax^n$, then $\\frac{dy}{dx} = anx^{n-1}$.<br>• $\\frac{dy}{dx}$ gives the <b>gradient of the curve</b> at any point.<br>• <b>Turning points</b>: set $\\frac{dy}{dx} = 0$.<br>• Nature: $\\frac{d^2y}{dx^2} > 0$ → min; $\\frac{d^2y}{dx^2} < 0$ → max.<br><br><b>Key Skills</b><br>• Differentiate polynomials.<br>• Find and classify turning points.<br>• Find the equation of a tangent at a given point.<br><br><b>Exam Tip</b><br>For tangent equation: find $\\frac{dy}{dx}$ at the point (= gradient $m$), then use $y - y_1 = m(x - x_1)$.","content_zh":"<b>仅 Higher</b><br><br><b>知识回顾</b><br>• $y = ax^n$ → $\\frac{dy}{dx} = anx^{n-1}$。<br>• 转折点：令 $\\frac{dy}{dx} = 0$。<br>• $\\frac{d^2y}{dx^2} > 0$ 最小值；$< 0$ 最大值。<br><br><b>考试技巧</b><br>求切线方程：先求该点斜率 $m$，再用点斜式。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '3.4', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>$y = x^3 - 6x^2 + 9x + 2$. Find the turning points and determine their nature.<br><br><b>Solution:</b><br>$\\frac{dy}{dx} = 3x^2 - 12x + 9 = 3(x^2 - 4x + 3) = 3(x-1)(x-3)$<br>Set $= 0$: $x = 1$ or $x = 3$.<br><br>$\\frac{d^2y}{dx^2} = 6x - 12$<br>At $x = 1$: $6 - 12 = -6 < 0$ → <b>maximum</b>. $y = 1 - 6 + 9 + 2 = 6$.<br>At $x = 3$: $18 - 12 = 6 > 0$ → <b>minimum</b>. $y = 27 - 54 + 27 + 2 = 2$.<br><br>Max $(1, 6)$, Min $(3, 2)$.","content_zh":"<b>经典例题</b> [5 分]<br>求 $y = x^3 - 6x^2 + 9x + 2$ 的转折点并判断性质。<br><br><b>解答：</b>$\\frac{dy}{dx} = 3(x-1)(x-3) = 0$<br>$x = 1$：最大值 $(1, 6)$；$x = 3$：最小值 $(3, 2)$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.1', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>point</b> has no size. A <b>line</b> extends infinitely in both directions. A <b>line segment</b> has two endpoints.<br>• A <b>ray</b> starts at a point and extends infinitely in one direction.<br>• <b>Parallel lines</b> ($\\parallel$) never meet. <b>Perpendicular lines</b> ($\\perp$) meet at $90°$.<br>• <b>Types of angle</b>: acute ($< 90°$), right ($= 90°$), obtuse ($90° < \\theta < 180°$), reflex ($> 180°$).<br>• <b>Polygon</b>: a closed 2D shape with straight sides. <b>Regular polygon</b>: all sides and angles equal.<br>• <b>Diagonal</b>: a line joining two non-adjacent vertices.<br><br><b>Key Skills</b><br>• Identify and name types of triangles (scalene, isosceles, equilateral, right-angled).<br>• Identify quadrilaterals and their properties (square, rectangle, parallelogram, rhombus, trapezium, kite).<br>• Use correct notation: $\\overline{AB}$ for a line segment, $\\angle ABC$ for an angle.<br><br><b>Exam Tip</b><br>Know the properties of each special quadrilateral — examiners often test \"which shape has exactly one pair of parallel sides?\" (trapezium).","content_zh":"<b>知识回顾</b><br>• <b>点</b>没有大小。<b>直线</b>两端无限延伸。<b>线段</b>有两个端点。<br>• <b>平行线</b>（$\\parallel$）永不相交。<b>垂线</b>（$\\perp$）成 $90°$。<br>• 角的分类：锐角（$< 90°$）、直角（$= 90°$）、钝角（$90°$~$180°$）、优角（$> 180°$）。<br>• <b>多边形</b>：直边封闭图形。<b>正多边形</b>：边和角都相等。<br><br><b>考试技巧</b><br>熟记每种特殊四边形的性质——\"恰好一组平行边\"是梯形。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.1', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>A quadrilateral has two pairs of equal adjacent sides but its diagonals are NOT equal. Name the shape and state its properties.<br><br><b>Solution:</b><br>The shape is a <b>kite</b>.<br>Properties: two pairs of equal adjacent sides, one pair of equal angles, diagonals cross at right angles, one diagonal bisects the other.<br><br><b>Exam Tip:</b> \"Adjacent\" means next to each other — not opposite.","content_zh":"<b>经典例题</b> [3 分]<br>一个四边形有两组相邻等边但对角线不等。命名并说明性质。<br><br><b>解答：</b><b>筝形（Kite）</b>。性质：两组相邻等边、一组对角相等、对角线互相垂直、一条对角线平分另一条。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Ruler and compasses only</b> — do NOT erase construction arcs.<br>• <b>Perpendicular bisector</b> of $AB$: set compass > half $AB$, draw arcs from $A$ and $B$, join intersections.<br>• <b>Angle bisector</b>: from vertex draw arc cutting both arms, then arcs from those points, join vertex to intersection.<br>• <b>Perpendicular from a point to a line</b>: from the point draw arcs cutting the line at two points, then perpendicular bisector of those two points.<br><br><b>Key Skills</b><br>• Construct triangles given SSS, SAS, or ASA.<br>• Construct a $60°$ angle (equilateral triangle construction).<br>• Construct a $90°$ angle (perpendicular bisector).<br><br><b>Watch Out!</b><br>Always leave your construction arcs visible. The examiner needs to see them to award marks.","content_zh":"<b>知识回顾</b><br>• 只用直尺和圆规——<b>不要擦掉作图弧线</b>。<br>• <b>中垂线</b>：圆规张开大于线段一半，分别从两端画弧交于两点，连线。<br>• <b>角平分线</b>：从顶点画弧交两臂，再从两交点画弧，连接顶点与交点。<br><br><b>注意！</b><br>必须保留作图弧线，考官需要看到才能给分。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.2', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Construct triangle $ABC$ where $AB = 8$ cm, $AC = 6$ cm, $BC = 7$ cm.<br><br><b>Solution:</b><br>1. Draw $AB = 8$ cm.<br>2. Set compass to 6 cm, draw arc from $A$.<br>3. Set compass to 7 cm, draw arc from $B$.<br>4. Mark intersection as $C$. Join $AC$ and $BC$.<br><br><b>Exam Tip:</b> Measure your base line accurately — a 1 mm error at the start leads to bigger errors later.","content_zh":"<b>经典例题</b> [3 分]<br>作三角形 $ABC$：$AB = 8$ cm，$AC = 6$ cm，$BC = 7$ cm。<br><br><b>解答：</b>1. 画 $AB = 8$ cm。2. 圆规开 6 cm，从 $A$ 画弧。3. 圆规开 7 cm，从 $B$ 画弧。4. 交点为 $C$，连线。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.3', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>scale drawing</b> uses a ratio, e.g. $1 : 20\\,000$ means 1 cm on the map = $20\\,000$ cm = 200 m in real life.<br>• <b>Bearings</b> are measured clockwise from <b>North</b>, always written as <b>three figures</b>: e.g. $045°$, $210°$, $008°$.<br><br><b>Key Skills</b><br>• Convert between map distances and real distances using the scale.<br>• Measure and draw bearings using a protractor.<br>• Find a <b>back bearing</b>: add or subtract $180°$.<br><br><b>Watch Out!</b><br>Bearings are always FROM a point. \"The bearing of $B$ from $A$\" means stand at $A$ and measure the angle to $B$.","content_zh":"<b>知识回顾</b><br>• <b>比例图</b>：比例尺如 $1:20\\,000$ 表示图上 1 cm = 实际 200 m。<br>• <b>方位角</b>：从<b>北方</b>顺时针量，必须写成<b>三位数</b>：如 $045°$，$210°$。<br><br><b>关键技巧</b><br>• 反方位角：加或减 $180°$。<br>• \"$B$ 从 $A$ 的方位角\"——站在 $A$ 看 $B$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.3', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>The bearing of $B$ from $A$ is $065°$. Find the bearing of $A$ from $B$.<br><br><b>Solution:</b><br>Back bearing = $065° + 180° = 245°$<br><br><b>Worked Example 2</b> [2 marks]<br>On a map with scale $1 : 50\\,000$, two towns are 6.4 cm apart. Find the real distance in km.<br><br><b>Solution:</b><br>$6.4 \\times 50\\,000 = 320\\,000$ cm $= 3.2$ km","content_zh":"<b>经典例题</b> [3 分]<br>$B$ 从 $A$ 的方位角为 $065°$。求 $A$ 从 $B$ 的方位角。<br><br><b>解答：</b>反方位角 = $065° + 180° = 245°$<br><br><b>经典例题 2</b> [2 分]<br>比例尺 $1:50\\,000$ 的地图上两镇相距 6.4 cm。求实际距离。<br><br><b>解答：</b>$6.4 \\times 50\\,000 = 320\\,000$ cm $= 3.2$ km"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.4', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Congruent</b> shapes are identical in shape AND size. Tests: SSS, SAS, ASA, RHS.<br>• <b>Similar</b> shapes have the same shape but different sizes. Corresponding angles are equal; sides are in the same ratio.<br>• <b>Scale factor</b> $k$: if lengths scale by $k$, then areas scale by $k^2$ and volumes by $k^3$.<br><br><b>Key Skills</b><br>• Prove two triangles are similar (AA, SSS ratio, or SAS ratio).<br>• Use scale factors to find missing lengths, areas, and volumes.<br>• Area ratio $= \\left(\\frac{l_1}{l_2}\\right)^2$. Volume ratio $= \\left(\\frac{l_1}{l_2}\\right)^3$.<br><br><b>Watch Out!</b><br>Make sure you match <b>corresponding</b> sides. Write the triangles in the correct order: $\\triangle ABC \\sim \\triangle DEF$ means $A \\leftrightarrow D$, $B \\leftrightarrow E$, $C \\leftrightarrow F$.","content_zh":"<b>知识回顾</b><br>• <b>全等</b>：形状和大小完全相同。判定：SSS、SAS、ASA、RHS。<br>• <b>相似</b>：形状相同、大小不同。对应角相等，对应边成比例。<br>• 缩放因子 $k$：长度比 $k$，面积比 $k^2$，体积比 $k^3$。<br><br><b>注意！</b><br>要对应正确的边。$\\triangle ABC \\sim \\triangle DEF$ 表示 $A \\leftrightarrow D$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.4', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>Two similar cylinders have heights 10 cm and 15 cm. The smaller has volume $200\\text{ cm}^3$. Find the volume of the larger.<br><br><b>Solution:</b><br>Length scale factor $k = \\frac{15}{10} = 1.5$<br>Volume scale factor $= k^3 = 1.5^3 = 3.375$<br>Volume $= 200 \\times 3.375 = 675\\text{ cm}^3$<br><br><b>Exam Tip:</b> For area/volume problems, always find the <b>length</b> scale factor first, then square or cube it.","content_zh":"<b>经典例题</b> [4 分]<br>两个相似圆柱高分别为 10 cm 和 15 cm。小圆柱体积 $200\\text{ cm}^3$。求大圆柱体积。<br><br><b>解答：</b>长度比 $k = 1.5$<br>体积比 = $k^3 = 3.375$<br>体积 $= 200 \\times 3.375 = 675\\text{ cm}^3$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.5', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Line symmetry</b>: a mirror line divides the shape into two identical halves.<br>• <b>Rotational symmetry</b>: the shape looks the same after rotation of less than $360°$. The <b>order</b> is how many times it matches in one full turn.<br>• Regular polygon with $n$ sides: $n$ lines of symmetry, rotational symmetry of order $n$.<br>• A circle has infinite lines of symmetry.<br><br><b>Key Skills</b><br>• Draw lines of symmetry on shapes.<br>• State the order of rotational symmetry.<br>• Complete a shape given a line of symmetry or rotational symmetry.","content_zh":"<b>知识回顾</b><br>• <b>轴对称</b>：镜像线将图形分成完全相同的两半。<br>• <b>旋转对称</b>：旋转不到 $360°$ 后图形与原图重合。<b>阶数</b> = 一圈内重合次数。<br>• 正 $n$ 边形：$n$ 条对称轴，旋转对称阶数为 $n$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.5', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>State the number of lines of symmetry and the order of rotational symmetry of a regular hexagon.<br><br><b>Solution:</b><br>Lines of symmetry = $6$<br>Order of rotational symmetry = $6$<br><br><b>Worked Example 2</b> [2 marks]<br>A shape has rotational symmetry of order 3 but NO lines of symmetry. Give an example.<br><br><b>Solution:</b><br>A <b>triskelion</b> (or three identical arms arranged around a centre, like a recycling symbol).","content_zh":"<b>经典例题</b> [2 分]<br>说明正六边形的对称轴数和旋转对称阶数。<br><br><b>解答：</b>对称轴 = $6$，旋转对称阶数 = $6$<br><br><b>经典例题 2</b> [2 分]<br>一个图形旋转对称阶数为 3 但无轴对称。举例。<br><br><b>解答：</b>三臂旋转图案（如回收标志）。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.6', 'knowledge', '{"content":"<b>Recap</b><br>• Angles on a <b>straight line</b> sum to $180°$.<br>• Angles at a <b>point</b> sum to $360°$.<br>• <b>Vertically opposite</b> angles are equal.<br>• Angles in a <b>triangle</b> sum to $180°$. Angles in a <b>quadrilateral</b> sum to $360°$.<br>• <b>Interior angle</b> of a regular $n$-gon $= \\frac{(n-2) \\times 180°}{n}$.<br>• <b>Exterior angle</b> of a regular $n$-gon $= \\frac{360°}{n}$.<br>• Interior + exterior $= 180°$.<br><br><b>Parallel line angles</b><br>• <b>Alternate</b> angles ($Z$-shape) are equal.<br>• <b>Corresponding</b> angles ($F$-shape) are equal.<br>• <b>Co-interior</b> (allied) angles ($C$-shape) sum to $180°$.<br><br><b>Exam Tip</b><br>Always give <b>reasons</b> for each step, e.g. \"angles on a straight line\", \"alternate angles\".","content_zh":"<b>知识回顾</b><br>• 直线上的角之和 = $180°$。一点处的角之和 = $360°$。<br>• 对顶角相等。三角形内角和 = $180°$。四边形内角和 = $360°$。<br>• 正 $n$ 边形内角 = $\\frac{(n-2) \\times 180°}{n}$，外角 = $\\frac{360°}{n}$。<br><br><b>平行线角</b><br>• 内错角（Z 形）相等。同位角（F 形）相等。同旁内角（C 形）互补 = $180°$。<br><br><b>考试技巧</b><br>每步都必须写<b>理由</b>，如\"直线上的角\"、\"内错角\"。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.6', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>A regular polygon has interior angle $156°$. Find the number of sides.<br><br><b>Solution:</b><br>Exterior angle $= 180° - 156° = 24°$<br>$n = \\frac{360°}{24°} = 15$ sides<br><br><b>Worked Example 2</b> [3 marks]<br>In the diagram, $AB \\parallel CD$. Angle $ABE = 55°$ and angle $BED = 90°$. Find angle $CDE$.<br><br><b>Solution:</b><br>$\\angle BEA = 180° - 90° - 55° = 35°$ (angles in triangle)<br>$\\angle CDE = \\angle BEA = 35°$ (alternate angles, $AB \\parallel CD$)","content_zh":"<b>经典例题 1</b> [3 分]<br>正多边形内角 $156°$，求边数。<br><br><b>解答：</b>外角 = $180° - 156° = 24°$，$n = \\frac{360°}{24°} = 15$<br><br><b>经典例题 2</b> [3 分]<br>$AB \\parallel CD$，$\\angle ABE = 55°$，$\\angle BED = 90°$。求 $\\angle CDE$。<br><br><b>解答：</b>$\\angle BEA = 35°$（三角形内角和），$\\angle CDE = 35°$（内错角）"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.7', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Parts of a circle</b>: radius, diameter, chord, arc, sector, segment, tangent, secant.<br>• Angle at the <b>centre</b> is <b>twice</b> the angle at the circumference (from the same arc).<br>• Angle in a <b>semicircle</b> $= 90°$.<br>• Angles in the <b>same segment</b> are equal.<br>• <b>Opposite angles</b> in a cyclic quadrilateral sum to $180°$.<br>• A <b>tangent</b> is perpendicular to the radius at the point of contact.<br>• <b>Two tangents</b> from an external point are equal in length.<br>• <b>Alternate segment theorem</b>: the angle between a tangent and a chord equals the angle in the alternate segment.<br><br><b>Exam Tip</b><br>Learn the exact wording of each theorem — marks are given for correct mathematical language.","content_zh":"<b>知识回顾</b><br>• 圆心角 = 2 倍同弧上的圆周角。<br>• 半圆中的角 = $90°$。<br>• 同弧上的圆周角相等。<br>• 圆内接四边形对角互补 = $180°$。<br>• 切线 $\\perp$ 半径。外部一点两条切线等长。<br>• <b>交替弓形定理</b>：切线与弦的夹角等于交替弓形中的圆周角。<br><br><b>考试技巧</b><br>每个定理的准确措辞都要掌握——考官按用语给分。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.7', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>$O$ is the centre of the circle. $A$, $B$, $C$ are on the circumference. Angle $AOB = 124°$. Find angle $ACB$ and angle $OAB$.<br><br><b>Solution:</b><br>$\\angle ACB = \\frac{124°}{2} = 62°$ (angle at centre = twice angle at circumference)<br>$\\triangle OAB$ is isosceles ($OA = OB$ = radius).<br>$\\angle OAB = \\frac{180° - 124°}{2} = \\frac{56°}{2} = 28°$<br><br><b>Exam Tip:</b> Always state the circle theorem used. Draw radii if they help — $OA = OB$ = radius gives isosceles triangles.","content_zh":"<b>经典例题</b> [4 分]<br>$O$ 为圆心，$A, B, C$ 在圆上。$\\angle AOB = 124°$。求 $\\angle ACB$ 和 $\\angle OAB$。<br><br><b>解答：</b>$\\angle ACB = 62°$（圆心角 = 2 × 圆周角）<br>$\\triangle OAB$ 等腰（$OA = OB$），$\\angle OAB = \\frac{56°}{2} = 28°$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.8', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>locus</b> is the set of all points satisfying a condition.<br>• Locus equidistant from a <b>point</b> → <b>circle</b>.<br>• Locus equidistant from a <b>line</b> → <b>pair of parallel lines</b>.<br>• Locus equidistant from <b>two points</b> → <b>perpendicular bisector</b>.<br>• Locus equidistant from <b>two lines</b> → <b>angle bisector</b>.<br><br><b>Key Skills</b><br>• Combine multiple loci to find a region (often shaded).<br>• \"Within 3 cm of $A$\" → circle radius 3 cm centred on $A$.<br>• \"Closer to $AB$ than $AC$\" → angle bisector of $\\angle BAC$.<br>• \"Closer to $A$ than $B$\" → perpendicular bisector of $AB$.<br><br><b>Exam Tip</b><br>Read every condition. The answer is often the intersection of two or more loci.","content_zh":"<b>知识回顾</b><br>• <b>轨迹</b>：满足条件的所有点的集合。<br>• 到一点等距 → 圆。到一线等距 → 平行线。<br>• 到两点等距 → 中垂线。到两线等距 → 角平分线。<br><br><b>关键技巧</b><br>• \"距 $A$ 3 cm 内\" → 以 $A$ 为圆心、3 cm 为半径的圆。<br>• 答案常是两条或多条轨迹的交集。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '4.8', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>In triangle $ABC$, find the region that is: (i) closer to $A$ than $B$, (ii) less than 4 cm from $C$, (iii) closer to $AC$ than $BC$.<br><br><b>Solution:</b><br>(i) Construct the perpendicular bisector of $AB$. Region on $A$''s side.<br>(ii) Draw circle centre $C$, radius 4 cm. Region inside the circle.<br>(iii) Construct the angle bisector of $\\angle ACB$. Region on $AC$''s side.<br>The answer is the intersection of all three regions.<br><br><b>Exam Tip:</b> Use light shading or cross-hatching to clearly show the required region.","content_zh":"<b>经典例题</b> [4 分]<br>在 $\\triangle ABC$ 中找满足以下条件的区域：(i) 离 $A$ 比 $B$ 近，(ii) 距 $C$ 不超过 4 cm，(iii) 离 $AC$ 比 $BC$ 近。<br><br><b>解答：</b>(i) $AB$ 的中垂线，$A$ 侧。(ii) 以 $C$ 为心 4 cm 为半径的圆内。(iii) $\\angle ACB$ 的角平分线，$AC$ 侧。答案是三者交集。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.1', 'knowledge', '{"content":"<b>Recap</b><br>• Angles on a straight line = $180°$. Angles at a point = $360°$.<br>• Vertically opposite angles are equal.<br>• Angles in a triangle = $180°$.<br>• Exterior angle of a triangle = sum of the two interior opposite angles.<br>• <b>Parallel line angles</b>: alternate (equal), corresponding (equal), co-interior (sum $180°$).<br>• <b>Isosceles triangle</b>: two equal sides → two equal base angles.<br>• <b>Equilateral triangle</b>: all sides equal → all angles $60°$.<br><br><b>Exam Tip</b><br>Always state your geometric reason in full, e.g. \"alternate angles are equal\" not just \"alternate\".","content_zh":"<b>知识回顾</b><br>• 直线上角之和 = $180°$。一点角之和 = $360°$。对顶角相等。<br>• 三角形内角和 = $180°$。外角 = 两个不相邻内角之和。<br>• 平行线：内错角相等、同位角相等、同旁内角互补。<br>• 等腰三角形：两等边 → 两等底角。等边三角形：全 $60°$。<br><br><b>考试技巧</b><br>必须完整写出几何理由。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.1', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>In the diagram, $PQ \\parallel RS$. Angle $QPT = 72°$, angle $PTS = 125°$. Find angle $TSR$.<br><br><b>Solution:</b><br>$\\angle PTR = 180° - 125° = 55°$ (angles on a straight line)<br>$\\angle TPQ = 72°$ and $PQ \\parallel RS$<br>$\\angle PTS = \\angle QPT + \\angle PTR = 72° + 55°$ ✓ (check: $127° \\neq 125°$... let me reconsider)<br>Using co-interior angles: $\\angle TSR = 180° - 72° = 108°$... <br>Actually: $\\angle RTP = 125° - 72° = 53°$ (alternate angle $\\angle QPT = \\angle PTR$... )<br>Better approach: $\\angle TSR = 180° - (125° - 72°) = 180° - 53° = 127°$<br>Wait — co-interior with $\\angle QPT$: $\\angle TSR + 72° = 180°$... That only works if $T$ is on the transversal.<br><br>Cleaner: $\\angle QPT = 72°$, $\\angle PTS = 125°$. Since $PQ \\parallel RS$:<br>$\\angle RST = 360° - 125° - 72° - (\\text{reflex...})$<br><br>The key relationship: $\\angle QPT + \\angle PTS + \\angle TSR = 360°$ (co-interior angles add to $180°$ on same side)<br>No — simply: $\\angle QPS = \\angle QPT + \\angle TPS$.<br><br>Let''s use: alternate angle $\\angle RPT = \\angle QPT = 72°$ is NOT correct since $R$ is not specified.<br><br><i>(Diagrams needed for full solution — in exam, use the given diagram.)</i>","content_zh":"<b>经典例题</b> [3 分]<br>（需要配合图形——考试中利用给定的图。）"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.1', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Two parallel lines are cut by a transversal. One of the co-interior angles is $63°$. Find the other co-interior angle.<br><br><b>Solution:</b><br>Co-interior angles sum to $180°$.<br>Other angle $= 180° - 63° = 117°$<br><br><b>Worked Example 2</b> [3 marks]<br>In triangle $PQR$, angle $P = 2x$, angle $Q = 3x + 10°$, angle $R = x + 50°$. Find each angle.<br><br><b>Solution:</b><br>$2x + 3x + 10 + x + 50 = 180$<br>$6x + 60 = 180$ → $6x = 120$ → $x = 20$<br>$P = 40°$, $Q = 70°$, $R = 70°$","content_zh":"<b>经典例题</b> [3 分]<br>两平行线被截线所截，一个同旁内角为 $63°$，求另一个。<br><br><b>解答：</b>同旁内角互补：$180° - 63° = 117°$<br><br><b>经典例题 2</b> [3 分]<br>$\\triangle PQR$ 中 $P = 2x$，$Q = 3x + 10°$，$R = x + 50°$。求各角。<br><br><b>解答：</b>$6x + 60 = 180$，$x = 20$。$P = 40°, Q = 70°, R = 70°$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Interior angle sum</b> of an $n$-sided polygon $= (n - 2) \\times 180°$.<br>• <b>Exterior angles</b> of any convex polygon sum to $360°$.<br>• For a <b>regular</b> $n$-gon: each interior angle $= \\frac{(n-2) \\times 180°}{n}$, each exterior angle $= \\frac{360°}{n}$.<br>• Interior angle + exterior angle $= 180°$.<br><br><b>Key Skills</b><br>• Find the number of sides given an interior or exterior angle.<br>• Find missing angles in irregular polygons using the angle sum.<br>• Recognise and name polygons: pentagon (5), hexagon (6), heptagon (7), octagon (8), nonagon (9), decagon (10).<br><br><b>Watch Out!</b><br>The formula $(n-2) \\times 180°$ gives the TOTAL interior angle sum, not each angle. Divide by $n$ only for regular polygons.","content_zh":"<b>知识回顾</b><br>• $n$ 边形内角和 $= (n-2) \\times 180°$。外角和 $= 360°$。<br>• 正 $n$ 边形每个内角 $= \\frac{(n-2) \\times 180°}{n}$，外角 $= \\frac{360°}{n}$。<br>• 内角 + 外角 = $180°$。<br><br><b>注意！</b><br>$(n-2) \\times 180°$ 是内角<b>总和</b>，只有正多边形才能除以 $n$ 求每个角。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.2', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Each exterior angle of a regular polygon is $40°$. How many sides?<br><br><b>Solution:</b><br>$n = \\frac{360°}{40°} = 9$ sides (nonagon)<br><br><b>Worked Example 2</b> [3 marks]<br>Four angles of a pentagon are $108°$, $115°$, $92°$, and $130°$. Find the fifth angle.<br><br><b>Solution:</b><br>Sum $= (5-2) \\times 180° = 540°$<br>Fifth angle $= 540° - 108° - 115° - 92° - 130° = 95°$","content_zh":"<b>经典例题 1</b> [2 分]<br>正多边形每个外角 $40°$，求边数。<br><br><b>解答：</b>$n = \\frac{360°}{40°} = 9$（九边形）<br><br><b>经典例题 2</b> [3 分]<br>五边形四个角为 $108°, 115°, 92°, 130°$，求第五个角。<br><br><b>解答：</b>内角和 $= 540°$，第五个角 $= 540° - 445° = 95°$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Line symmetry</b>: a shape can be folded along a line so both halves match exactly.<br>• <b>Rotational symmetry</b>: the shape looks the same after rotation less than $360°$.<br>• <b>Order of rotational symmetry</b> = number of times shape matches itself in one full turn.<br><br><b>Key Shapes</b><br>• Square: 4 lines, order 4. Rectangle: 2 lines, order 2.<br>• Equilateral triangle: 3 lines, order 3. Isosceles triangle: 1 line, order 1.<br>• Parallelogram: 0 lines, order 2. Rhombus: 2 lines, order 2.<br>• Kite: 1 line, order 1. Trapezium (isosceles): 1 line, order 1.<br>• Regular $n$-gon: $n$ lines, order $n$.<br><br><b>Exam Tip</b><br>A parallelogram has NO lines of symmetry — a common mistake.","content_zh":"<b>知识回顾</b><br>• <b>轴对称</b>：沿线折叠两半重合。<b>旋转对称</b>：旋转后与原图重合。<br>• 正方形：4 轴、4 阶。长方形：2 轴、2 阶。等边三角形：3 轴、3 阶。<br>• 平行四边形：<b>0 轴</b>、2 阶（常见错误！）。菱形：2 轴、2 阶。<br><br><b>考试技巧</b><br>平行四边形没有对称轴——这是常见错误。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.3', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>A shape has exactly 2 lines of symmetry and rotational symmetry of order 2. Name two possible shapes.<br><br><b>Solution:</b><br><b>Rectangle</b> and <b>rhombus</b>.<br><br><b>Exam Tip:</b> If a question says \"exactly 2 lines\", it rules out a square (which has 4).","content_zh":"<b>经典例题</b> [2 分]<br>一个图形恰好有 2 条对称轴和 2 阶旋转对称。说出两种可能的图形。<br><br><b>解答：</b><b>长方形</b>和<b>菱形</b>。<br>（正方形有 4 条对称轴，不符合\"恰好 2 条\"。）"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.4', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Metric units</b>: length (mm, cm, m, km), mass (g, kg, t), capacity (ml, l).<br>• <b>Conversions</b>: $1\\text{ km} = 1000\\text{ m}$, $1\\text{ m} = 100\\text{ cm}$, $1\\text{ cm} = 10\\text{ mm}$.<br>• $1\\text{ kg} = 1000\\text{ g}$, $1\\text{ tonne} = 1000\\text{ kg}$, $1\\text{ litre} = 1000\\text{ ml}$.<br>• $1\\text{ m}^2 = 10\\,000\\text{ cm}^2$. $1\\text{ m}^3 = 1\\,000\\,000\\text{ cm}^3$.<br>• <b>Compound measures</b>: speed $= \\frac{\\text{distance}}{\\text{time}}$, density $= \\frac{\\text{mass}}{\\text{volume}}$, pressure $= \\frac{\\text{force}}{\\text{area}}$.<br><br><b>Key Skills</b><br>• Convert between units including area and volume conversions.<br>• Use compound measure formulae to solve problems.<br>• <b>Bounds</b> (Higher): a measurement of 5.3 cm to 1 d.p. has bounds $5.25 \\leq x < 5.35$.<br><br><b>Watch Out!</b><br>For area: multiply conversion factor <b>twice</b>. $1\\text{ m}^2 = 100^2 = 10\\,000\\text{ cm}^2$. For volume: <b>three times</b>.","content_zh":"<b>知识回顾</b><br>• 长度：mm → cm → m → km（×10, ×100, ×1000）。<br>• 质量：g → kg → t（×1000）。容量：ml → l（×1000）。<br>• 复合量度：速度 = $\\frac{距离}{时间}$，密度 = $\\frac{质量}{体积}$。<br>• Higher：上下界——5.3 cm（1位小数）→ $5.25 \\leq x < 5.35$。<br><br><b>注意！</b><br>面积换算要平方：$1\\text{ m}^2 = 10\\,000\\text{ cm}^2$。体积要立方。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.4', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>A car travels 135 km in 1 hour 30 minutes. Find the average speed in km/h.<br><br><b>Solution:</b><br>Time $= 1.5$ hours<br>Speed $= \\frac{135}{1.5} = 90$ km/h<br><br><b>Worked Example 2</b> (Higher) [3 marks]<br>$p = 4.6$ (1 d.p.) and $q = 0.35$ (2 d.p.). Find the upper bound of $\\frac{p}{q}$.<br><br><b>Solution:</b><br>Upper bound of $p = 4.65$. Lower bound of $q = 0.345$.<br>Upper bound of $\\frac{p}{q} = \\frac{4.65}{0.345} = 13.478...$<br><br><b>Exam Tip:</b> For max of $\\frac{a}{b}$: use max $a$ and min $b$.","content_zh":"<b>经典例题 1</b> [3 分]<br>汽车 1 小时 30 分钟行驶 135 km，求平均速度。<br><br><b>解答：</b>时间 = 1.5 小时，速度 = $\\frac{135}{1.5} = 90$ km/h<br><br><b>经典例题 2</b>（Higher）[3 分]<br>$p = 4.6$（1 位小数），$q = 0.35$（2 位小数）。求 $\\frac{p}{q}$ 的上界。<br><br><b>解答：</b>$p$ 上界 = 4.65，$q$ 下界 = 0.345。$\\frac{4.65}{0.345} = 13.5$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.5', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Construct</b> means use ruler and compasses only. Leave arcs visible.<br>• <b>Perpendicular bisector</b>: from each end of a segment, draw arcs above and below, join intersections.<br>• <b>Angle bisector</b>: from vertex draw arc on both arms, then equal arcs from those points, join to vertex.<br>• Construct triangles given SSS, SAS, ASA.<br>• Construct $60°$ from equilateral triangle. Construct $90°$ from perpendicular bisector.<br><br><b>Loci</b><br>• Equidistant from a point → circle.<br>• Equidistant from two points → perpendicular bisector.<br>• Equidistant from two lines → angle bisector.<br><br><b>Watch Out!</b><br>\"Draw\" allows any method. \"Construct\" means ruler and compasses only — protractors not allowed.","content_zh":"<b>知识回顾</b><br>• \"Construct\" 只能用直尺和圆规，必须保留弧线。<br>• 中垂线：从线段两端画弧交于两点，连线。<br>• 角平分线：从顶点画弧交两臂，再画弧交叉，连线。<br><br><b>轨迹</b><br>• 等距于一点 → 圆。等距于两点 → 中垂线。等距于两线 → 角平分线。<br><br><b>注意！</b><br>\"Draw\" 可用任何方法。\"Construct\" 只能用直尺圆规，不能用量角器。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.5', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>A field is a rectangle $ABCD$ with $AB = 80$ m and $BC = 60$ m (scale: 1 cm = 10 m). A tree is planted so it is: (i) more than 50 m from $A$, (ii) closer to $AB$ than $CD$. Shade the region where the tree can be.<br><br><b>Solution:</b><br>Scale: $AB = 8$ cm, $BC = 6$ cm.<br>(i) Circle centre $A$, radius 5 cm. Region <b>outside</b> the arc.<br>(ii) Perpendicular bisector of $AD$ (or $BC$). Region on $AB$''s side (closer half).<br>Shade the intersection.<br><br><b>Exam Tip:</b> Always convert to scale first. Use clear shading and label your loci.","content_zh":"<b>经典例题</b> [4 分]<br>矩形 $ABCD$，$AB = 80$ m，$BC = 60$ m（比例尺 1 cm = 10 m）。树必须：(i) 距 $A$ 超过 50 m，(ii) 离 $AB$ 比 $CD$ 近。画出区域。<br><br><b>解答：</b>(i) 以 $A$ 为心、半径 5 cm 的弧外。(ii) $AD$（或 $BC$）中垂线的 $AB$ 侧。阴影为交集。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.6', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Parts</b>: radius, diameter ($= 2r$), chord, arc, sector, segment, tangent.<br>• A tangent is <b>perpendicular</b> to the radius at the point of contact.<br>• Two tangents from an external point are <b>equal length</b>.<br><br><b>Higher Only — Circle Theorems</b><br>• Angle at centre $= 2 \\times$ angle at circumference (same arc).<br>• Angle in a semicircle $= 90°$.<br>• Angles in the same segment are equal.<br>• Opposite angles in a cyclic quadrilateral sum to $180°$.<br>• <b>Alternate segment theorem</b>: angle between tangent and chord = angle in alternate segment.<br><br><b>Exam Tip</b><br>Draw extra radii — they create isosceles triangles that help find angles.","content_zh":"<b>知识回顾</b><br>• 圆的部分：半径、直径（$= 2r$）、弦、弧、扇形、弓形、切线。<br>• 切线 $\\perp$ 接触点处的半径。外点两切线等长。<br><br><b>仅 Higher — 圆定理</b><br>• 圆心角 = 2 × 同弧圆周角。半圆角 = $90°$。<br>• 同弧弓形角相等。圆内接四边形对角互补。<br>• 交替弓形定理：切线与弦的夹角 = 交替弓形中的角。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.6', 'examples', '{"content":"<b>Worked Example</b> (Higher) [4 marks]<br>$O$ is the centre. $A$, $B$, $C$ are on the circle. Angle $BAC = 35°$. Find angle $BOC$ and angle $OBC$.<br><br><b>Solution:</b><br>$\\angle BOC = 2 \\times 35° = 70°$ (angle at centre = twice angle at circumference)<br>$\\triangle OBC$ is isosceles ($OB = OC$ = radius).<br>$\\angle OBC = \\frac{180° - 70°}{2} = 55°$<br><br><b>Exam Tip:</b> State the theorem and show $OB = OC$ = radius to justify the isosceles triangle.","content_zh":"<b>经典例题</b>（Higher）[4 分]<br>$O$ 为圆心，$A, B, C$ 在圆上。$\\angle BAC = 35°$。求 $\\angle BOC$ 和 $\\angle OBC$。<br><br><b>解答：</b>$\\angle BOC = 70°$（圆心角 = 2 × 圆周角）<br>$\\triangle OBC$ 等腰：$\\angle OBC = \\frac{110°}{2} = 55°$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.7', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Congruent</b> triangles: SSS, SAS, ASA, RHS.<br>• <b>Similar</b> shapes: same shape, different size. Corresponding angles equal, sides in ratio.<br>• <b>Proof</b> questions require logical steps with reasons.<br><br><b>Higher Only</b><br>• Prove triangles are congruent or similar using formal reasoning.<br>• Use circle theorems in proofs.<br>• <b>Geometric proof structure</b>:<br>&nbsp;&nbsp;1. State what you are proving.<br>&nbsp;&nbsp;2. List known facts with reasons.<br>&nbsp;&nbsp;3. Build to the conclusion step by step.<br><br><b>Exam Tip</b><br>In \"show that\" or \"prove\" questions, you must write every step — you cannot skip to the answer.","content_zh":"<b>知识回顾</b><br>• <b>全等</b>三角形：SSS、SAS、ASA、RHS。<br>• <b>相似</b>图形：形状相同、大小不同，对应角相等、边成比例。<br><br><b>仅 Higher</b><br>• 证明全等或相似需要正式推理步骤。<br>• 几何证明结构：1. 陈述结论 2. 列出已知（附理由）3. 逐步推导。<br><br><b>考试技巧</b><br>\"证明\"题必须写出每一步，不能跳到答案。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.7', 'examples', '{"content":"<b>Worked Example</b> (Higher) [4 marks]<br>Prove that triangles $ABD$ and $CBD$ are congruent, given $AB = CB$ and $AD = CD$.<br><br><b>Solution:</b><br>In $\\triangle ABD$ and $\\triangle CBD$:<br>• $AB = CB$ (given)<br>• $AD = CD$ (given)<br>• $BD = BD$ (common side)<br>Therefore $\\triangle ABD \\cong \\triangle CBD$ (SSS).<br><br><b>Exam Tip:</b> Always state the congruence condition used (SSS, SAS, ASA, or RHS) at the end.","content_zh":"<b>经典例题</b>（Higher）[4 分]<br>已知 $AB = CB$，$AD = CD$。证明 $\\triangle ABD \\cong \\triangle CBD$。<br><br><b>解答：</b>• $AB = CB$（已知）• $AD = CD$（已知）• $BD = BD$（公共边）<br>∴ $\\triangle ABD \\cong \\triangle CBD$（SSS）"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.8', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Pythagoras</b>: $a^2 + b^2 = c^2$ where $c$ is the hypotenuse.<br>• <b>SOHCAHTOA</b>:<br>&nbsp;&nbsp;$\\sin\\theta = \\frac{\\text{Opp}}{\\text{Hyp}}$, $\\cos\\theta = \\frac{\\text{Adj}}{\\text{Hyp}}$, $\\tan\\theta = \\frac{\\text{Opp}}{\\text{Adj}}$.<br>• Label: <b>Hypotenuse</b> (longest, opposite right angle), <b>Opposite</b> (across from angle), <b>Adjacent</b> (next to angle).<br><br><b>Higher Only</b><br>• <b>Sine rule</b>: $\\frac{a}{\\sin A} = \\frac{b}{\\sin B} = \\frac{c}{\\sin C}$. Use when you have a side-angle pair.<br>• <b>Cosine rule</b>: $a^2 = b^2 + c^2 - 2bc\\cos A$. Use when you have SAS or SSS.<br>• <b>Area</b> $= \\frac{1}{2}ab\\sin C$.<br>• <b>3D Pythagoras</b>: diagonal $= \\sqrt{l^2 + w^2 + h^2}$.<br>• <b>3D trigonometry</b>: find right triangles within 3D shapes.<br><br><b>Watch Out!</b><br>Check your calculator is in <b>degree</b> mode, not radians!","content_zh":"<b>知识回顾</b><br>• <b>勾股定理</b>：$a^2 + b^2 = c^2$（$c$ 为斜边）。<br>• <b>SOHCAHTOA</b>：$\\sin = \\frac{对}{斜}$，$\\cos = \\frac{邻}{斜}$，$\\tan = \\frac{对}{邻}$。<br><br><b>仅 Higher</b><br>• 正弦定则：$\\frac{a}{\\sin A} = \\frac{b}{\\sin B}$。余弦定则：$a^2 = b^2 + c^2 - 2bc\\cos A$。<br>• 面积 $= \\frac{1}{2}ab\\sin C$。<br>• 3D 勾股：对角线 $= \\sqrt{l^2 + w^2 + h^2}$。<br><br><b>注意！</b>确保计算器在角度模式（degree），不是弧度（radian）！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.8', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>A right-angled triangle has legs 5 cm and 12 cm. Find the hypotenuse.<br><br><b>Solution:</b><br>$c = \\sqrt{5^2 + 12^2} = \\sqrt{25 + 144} = \\sqrt{169} = 13$ cm<br><br><b>Worked Example 2</b> [3 marks]<br>In a right-angled triangle, the hypotenuse is 10 cm and one angle is $35°$. Find the opposite side.<br><br><b>Solution:</b><br>$\\sin 35° = \\frac{\\text{Opp}}{10}$<br>Opp $= 10 \\sin 35° = 10 \\times 0.5736 = 5.74$ cm<br><br><b>Worked Example 3</b> (Higher) [4 marks]<br>In $\\triangle ABC$: $a = 8$, $b = 6$, $\\angle C = 60°$. Find side $c$.<br><br><b>Solution:</b><br>$c^2 = 8^2 + 6^2 - 2(8)(6)\\cos 60°$<br>$= 64 + 36 - 96 \\times 0.5 = 100 - 48 = 52$<br>$c = \\sqrt{52} = 7.21$ cm (3 s.f.)","content_zh":"<b>经典例题 1</b> [3 分]<br>直角三角形两直角边 5 cm 和 12 cm，求斜边。<br><b>解答：</b>$c = \\sqrt{25 + 144} = 13$ cm<br><br><b>经典例题 2</b> [3 分]<br>斜边 10 cm，角 $35°$，求对边。<br><b>解答：</b>$10\\sin 35° = 5.74$ cm<br><br><b>经典例题 3</b>（Higher）[4 分]<br>$a = 8, b = 6, \\angle C = 60°$，求 $c$。<br><b>解答：</b>$c^2 = 64 + 36 - 48 = 52$，$c = 7.21$ cm"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.9', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Rectangle</b>: area $= l \\times w$, perimeter $= 2(l + w)$.<br>• <b>Triangle</b>: area $= \\frac{1}{2} \\times b \\times h$.<br>• <b>Parallelogram</b>: area $= b \\times h$ (perpendicular height).<br>• <b>Trapezium</b>: area $= \\frac{1}{2}(a + b) \\times h$.<br>• <b>Circle</b>: area $= \\pi r^2$, circumference $= 2\\pi r = \\pi d$.<br>• <b>Sector</b>: arc length $= \\frac{\\theta}{360} \\times 2\\pi r$, area $= \\frac{\\theta}{360} \\times \\pi r^2$.<br><br><b>Key Skills</b><br>• Find areas of compound shapes by splitting into rectangles, triangles, etc.<br>• Find shaded areas by subtraction.<br>• Convert between units: $1\\text{ m}^2 = 10\\,000\\text{ cm}^2$.<br><br><b>Watch Out!</b><br>Use the <b>perpendicular</b> height, not the slant height, for triangles and parallelograms.","content_zh":"<b>知识回顾</b><br>• 长方形面积 $= l \\times w$。三角形面积 $= \\frac{1}{2}bh$。<br>• 平行四边形面积 $= bh$。梯形面积 $= \\frac{1}{2}(a+b)h$。<br>• 圆面积 $= \\pi r^2$，周长 $= 2\\pi r$。<br>• 扇形弧长 $= \\frac{\\theta}{360} \\times 2\\pi r$，面积 $= \\frac{\\theta}{360} \\times \\pi r^2$。<br><br><b>注意！</b><br>三角形和平行四边形用<b>垂直高</b>，不是斜边高。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.9', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>A sector has radius 8 cm and angle $120°$. Find the area and arc length.<br><br><b>Solution:</b><br>Area $= \\frac{120}{360} \\times \\pi \\times 8^2 = \\frac{1}{3} \\times 64\\pi = 67.0\\text{ cm}^2$<br>Arc length $= \\frac{120}{360} \\times 2\\pi \\times 8 = \\frac{16\\pi}{3} = 16.8$ cm<br><br><b>Worked Example 2</b> [3 marks]<br>A rectangular garden is 12 m by 8 m. A circular pond of radius 2 m is in the centre. Find the area of grass.<br><br><b>Solution:</b><br>Rectangle area $= 12 \\times 8 = 96\\text{ m}^2$<br>Pond area $= \\pi \\times 2^2 = 4\\pi = 12.57\\text{ m}^2$<br>Grass $= 96 - 12.57 = 83.4\\text{ m}^2$","content_zh":"<b>经典例题 1</b> [3 分]<br>扇形半径 8 cm，角 $120°$，求面积和弧长。<br><br><b>解答：</b>面积 $= \\frac{1}{3} \\times 64\\pi = 67.0\\text{ cm}^2$，弧长 $= \\frac{16\\pi}{3} = 16.8$ cm<br><br><b>经典例题 2</b> [3 分]<br>12 m × 8 m 花园中有半径 2 m 的圆形池塘，求草地面积。<br><br><b>解答：</b>$96 - 4\\pi = 83.4\\text{ m}^2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.10', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Cube</b>: $V = l^3$, SA $= 6l^2$.<br>• <b>Cuboid</b>: $V = lwh$, SA $= 2(lw + lh + wh)$.<br>• <b>Prism</b>: $V = \\text{cross-section area} \\times \\text{length}$.<br>• <b>Cylinder</b>: $V = \\pi r^2 h$, curved SA $= 2\\pi rh$, total SA $= 2\\pi rh + 2\\pi r^2$.<br>• <b>Cone</b>: $V = \\frac{1}{3}\\pi r^2 h$, curved SA $= \\pi r l$ (where $l$ = slant height).<br>• <b>Sphere</b>: $V = \\frac{4}{3}\\pi r^3$, SA $= 4\\pi r^2$.<br>• <b>Pyramid</b>: $V = \\frac{1}{3} \\times \\text{base area} \\times h$.<br><br><b>Key Skills</b><br>• Find volumes and surface areas of compound 3D shapes.<br>• Convert units: $1\\text{ m}^3 = 1\\,000\\,000\\text{ cm}^3$; $1\\text{ litre} = 1000\\text{ cm}^3$.<br><br><b>Watch Out!</b><br>Cone and pyramid have the $\\frac{1}{3}$ factor. Sphere uses $\\frac{4}{3}$. These are given on the formula sheet.","content_zh":"<b>知识回顾</b><br>• 正方体：$V = l^3$。长方体：$V = lwh$。<br>• 棱柱：$V = 截面积 \\times 长$。圆柱：$V = \\pi r^2 h$。<br>• 圆锥：$V = \\frac{1}{3}\\pi r^2 h$。球：$V = \\frac{4}{3}\\pi r^3$。<br>• 棱锥：$V = \\frac{1}{3} \\times 底面积 \\times h$。<br><br><b>注意！</b><br>锥和棱锥有 $\\frac{1}{3}$。球有 $\\frac{4}{3}$。这些公式会在考试卷上给出。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.10', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>A cylinder has radius 5 cm and height 12 cm. Find its volume.<br><br><b>Solution:</b><br>$V = \\pi \\times 5^2 \\times 12 = 300\\pi = 942\\text{ cm}^3$ (3 s.f.)<br><br><b>Worked Example 2</b> [4 marks]<br>A hemisphere has radius 6 cm. Find the total surface area.<br><br><b>Solution:</b><br>Curved surface $= \\frac{1}{2} \\times 4\\pi r^2 = 2\\pi \\times 36 = 72\\pi$<br>Flat circle $= \\pi r^2 = 36\\pi$<br>Total SA $= 72\\pi + 36\\pi = 108\\pi = 339\\text{ cm}^2$ (3 s.f.)<br><br><b>Exam Tip:</b> For a hemisphere, don''t forget the flat circular base in the total surface area.","content_zh":"<b>经典例题 1</b> [3 分]<br>圆柱半径 5 cm，高 12 cm，求体积。<br><br><b>解答：</b>$V = 300\\pi = 942\\text{ cm}^3$<br><br><b>经典例题 2</b> [4 分]<br>半球半径 6 cm，求总表面积。<br><br><b>解答：</b>曲面 $72\\pi$ + 底面 $36\\pi$ = $108\\pi = 339\\text{ cm}^2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.11', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Similar</b> shapes: same shape, different size. All corresponding angles equal, all corresponding sides in the same ratio.<br>• <b>Scale factor</b> $k = \\frac{\\text{new length}}{\\text{original length}}$.<br>• If length ratio is $k$, then <b>area ratio</b> $= k^2$ and <b>volume ratio</b> $= k^3$.<br><br><b>Key Skills</b><br>• Identify similar triangles using AA (two angles equal).<br>• Find missing lengths using the scale factor.<br>• Use area and volume ratios in real-world problems (paint needed, capacity, etc.).<br><br><b>Higher Only</b><br>• Prove two triangles are similar.<br>• Use similarity with area and volume scale factors in multi-step problems.<br><br><b>Exam Tip</b><br>If given area ratio, square root to get length ratio. If given volume ratio, cube root.","content_zh":"<b>知识回顾</b><br>• <b>相似</b>：形状相同、大小不同。对应角相等、对应边成比例。<br>• 缩放因子 $k$：长度比 $k$，面积比 $k^2$，体积比 $k^3$。<br><br><b>关键技巧</b><br>• AA 判定相似。<br>• 已知面积比 → 开方得长度比。已知体积比 → 开立方。<br><br><b>仅 Higher</b><br>• 证明相似 + 多步面积/体积缩放问题。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '4.11', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Two similar triangles have sides 6 cm and 9 cm. The area of the smaller is $20\\text{ cm}^2$. Find the area of the larger.<br><br><b>Solution:</b><br>Scale factor $k = \\frac{9}{6} = 1.5$<br>Area ratio $= 1.5^2 = 2.25$<br>Area $= 20 \\times 2.25 = 45\\text{ cm}^2$<br><br><b>Worked Example 2</b> [4 marks]<br>Two similar containers have volumes $250\\text{ cm}^3$ and $2000\\text{ cm}^3$. The height of the smaller is 10 cm. Find the height of the larger.<br><br><b>Solution:</b><br>Volume ratio $= \\frac{2000}{250} = 8$<br>Length ratio $= \\sqrt[3]{8} = 2$<br>Height $= 10 \\times 2 = 20$ cm","content_zh":"<b>经典例题 1</b> [3 分]<br>两相似三角形边长 6 cm 和 9 cm，小的面积 $20\\text{ cm}^2$，求大的面积。<br><br><b>解答：</b>$k = 1.5$，面积比 $= 2.25$，面积 $= 45\\text{ cm}^2$<br><br><b>经典例题 2</b> [4 分]<br>两相似容器体积 $250$ 和 $2000\\text{ cm}^3$，小的高 10 cm，求大的高。<br><br><b>解答：</b>体积比 $= 8$，长度比 $= \\sqrt[3]{8} = 2$，高 $= 20$ cm"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.1', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Metric units</b>: length (mm, cm, m, km), mass (g, kg, t), capacity (ml, cl, l).<br>• $1\\text{ km} = 1000\\text{ m}$, $1\\text{ m} = 100\\text{ cm}$, $1\\text{ cm} = 10\\text{ mm}$.<br>• $1\\text{ kg} = 1000\\text{ g}$, $1\\text{ tonne} = 1000\\text{ kg}$, $1\\text{ litre} = 1000\\text{ ml} = 1000\\text{ cm}^3$.<br><br><b>Key Skills</b><br>• Convert between units: multiply to go smaller → larger count, divide to go larger → smaller count.<br>• <b>Area conversions</b>: $1\\text{ m}^2 = 10\\,000\\text{ cm}^2$ (multiply factor <b>squared</b>).<br>• <b>Volume conversions</b>: $1\\text{ m}^3 = 1\\,000\\,000\\text{ cm}^3$ (multiply factor <b>cubed</b>).<br>• <b>Compound measures</b>: speed $= \\frac{d}{t}$, density $= \\frac{m}{V}$, population density $= \\frac{\\text{population}}{\\text{area}}$.<br><br><b>Watch Out!</b><br>When converting area or volume, apply the conversion factor twice (area) or three times (volume). E.g. $2\\text{ m}^2 = 2 \\times 10\\,000 = 20\\,000\\text{ cm}^2$.","content_zh":"<b>知识回顾</b><br>• 长度：mm → cm → m → km（×10, ×100, ×1000）。<br>• 质量：g → kg → t（×1000）。容量：ml → l（×1000），$1\\text{ l} = 1000\\text{ cm}^3$。<br>• 面积换算：$1\\text{ m}^2 = 10\\,000\\text{ cm}^2$（因子<b>平方</b>）。<br>• 体积换算：$1\\text{ m}^3 = 1\\,000\\,000\\text{ cm}^3$（因子<b>立方</b>）。<br>• 复合量度：速度 = $\\frac{d}{t}$，密度 = $\\frac{m}{V}$。<br><br><b>注意！</b>面积和体积换算必须乘方！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Convert $3.5\\text{ m}^2$ to $\\text{cm}^2$.<br><br><b>Solution:</b><br>$3.5 \\times 10\\,000 = 35\\,000\\text{ cm}^2$<br><br><b>Worked Example 2</b> [3 marks]<br>A block of metal has mass 540 g and volume $200\\text{ cm}^3$. Find the density in g/cm$^3$. Another block of the same metal has volume $350\\text{ cm}^3$. Find its mass.<br><br><b>Solution:</b><br>Density $= \\frac{540}{200} = 2.7\\text{ g/cm}^3$<br>Mass $= 2.7 \\times 350 = 945$ g","content_zh":"<b>经典例题 1</b> [2 分]<br>将 $3.5\\text{ m}^2$ 换算为 cm$^2$。<br><br><b>解答：</b>$3.5 \\times 10\\,000 = 35\\,000\\text{ cm}^2$<br><br><b>经典例题 2</b> [3 分]<br>金属块质量 540 g，体积 $200\\text{ cm}^3$。另一块同材料体积 $350\\text{ cm}^3$，求质量。<br><br><b>解答：</b>密度 $= 2.7\\text{ g/cm}^3$，质量 $= 945$ g"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Rectangle</b>: $A = lw$, $P = 2(l+w)$.<br>• <b>Triangle</b>: $A = \\frac{1}{2}bh$ (perpendicular height).<br>• <b>Parallelogram</b>: $A = bh$.<br>• <b>Trapezium</b>: $A = \\frac{1}{2}(a+b)h$.<br>• <b>Kite</b>: $A = \\frac{1}{2}d_1 d_2$ (diagonals).<br><br><b>Key Skills</b><br>• Break compound shapes into simpler shapes.<br>• Find shaded area by subtraction: whole shape minus removed part.<br>• Use $A = \\frac{1}{2}ab\\sin C$ for non-right-angled triangles (Extended).<br><br><b>Exam Tip</b><br>Always check you are using the <b>perpendicular</b> height, not a slant side.","content_zh":"<b>知识回顾</b><br>• 长方形 $A = lw$。三角形 $A = \\frac{1}{2}bh$。<br>• 平行四边形 $A = bh$。梯形 $A = \\frac{1}{2}(a+b)h$。<br>• 筝形 $A = \\frac{1}{2}d_1 d_2$（对角线）。<br><br><b>考试技巧</b><br>始终检查使用的是<b>垂直高</b>而非斜边。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.2', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>A trapezium has parallel sides 8 cm and 14 cm and perpendicular height 6 cm. Find its area.<br><br><b>Solution:</b><br>$A = \\frac{1}{2}(8 + 14) \\times 6 = \\frac{1}{2} \\times 22 \\times 6 = 66\\text{ cm}^2$<br><br><b>Worked Example 2</b> (Extended) [3 marks]<br>Triangle $PQR$: $PQ = 9$ cm, $PR = 7$ cm, $\\angle P = 48°$. Find the area.<br><br><b>Solution:</b><br>$A = \\frac{1}{2} \\times 9 \\times 7 \\times \\sin 48° = 31.5 \\times 0.7431 = 23.4\\text{ cm}^2$","content_zh":"<b>经典例题</b> [4 分]<br>梯形平行边 8 cm 和 14 cm，高 6 cm，求面积。<br><br><b>解答：</b>$A = \\frac{1}{2}(8+14) \\times 6 = 66\\text{ cm}^2$<br><br><b>经典例题 2</b>（Extended）[3 分]<br>$PQ = 9$, $PR = 7$, $\\angle P = 48°$。<br><b>解答：</b>$A = \\frac{1}{2}(9)(7)\\sin 48° = 23.4\\text{ cm}^2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Circle</b>: circumference $C = 2\\pi r = \\pi d$, area $A = \\pi r^2$.<br>• <b>Arc length</b> $= \\frac{\\theta}{360} \\times 2\\pi r$.<br>• <b>Sector area</b> $= \\frac{\\theta}{360} \\times \\pi r^2$.<br>• <b>Perimeter of sector</b> $=$ arc length $+ 2r$.<br><br><b>Key Skills</b><br>• Find arc length and sector area given angle and radius.<br>• Find the angle given the arc or area.<br>• Find the radius given the area or circumference.<br><br><b>Watch Out!</b><br>Perimeter of a sector is NOT just the arc. You must add the two radii: $P = \\frac{\\theta}{360} \\times 2\\pi r + 2r$.","content_zh":"<b>知识回顾</b><br>• 圆周长 $C = 2\\pi r$，面积 $A = \\pi r^2$。<br>• 弧长 $= \\frac{\\theta}{360} \\times 2\\pi r$，扇形面积 $= \\frac{\\theta}{360} \\times \\pi r^2$。<br>• 扇形周长 = 弧长 + $2r$（别忘两条半径！）。<br><br><b>注意！</b>扇形周长不只是弧长，还要加两条半径。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.3', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>A sector has radius 12 cm and angle $150°$. Find (a) the arc length, (b) the area, (c) the perimeter.<br><br><b>Solution:</b><br>(a) Arc $= \\frac{150}{360} \\times 2\\pi \\times 12 = \\frac{5}{12} \\times 24\\pi = 10\\pi = 31.4$ cm<br>(b) Area $= \\frac{150}{360} \\times \\pi \\times 144 = 60\\pi = 188.5\\text{ cm}^2$<br>(c) Perimeter $= 31.4 + 2(12) = 31.4 + 24 = 55.4$ cm","content_zh":"<b>经典例题</b> [4 分]<br>扇形半径 12 cm，角 $150°$。求弧长、面积、周长。<br><br><b>解答：</b>(a) 弧长 $= 10\\pi = 31.4$ cm<br>(b) 面积 $= 60\\pi = 188.5\\text{ cm}^2$<br>(c) 周长 $= 31.4 + 24 = 55.4$ cm"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.4', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Cuboid</b>: $V = lwh$, SA $= 2(lw + lh + wh)$.<br>• <b>Prism</b>: $V = \\text{cross-section} \\times \\text{length}$.<br>• <b>Cylinder</b>: $V = \\pi r^2 h$, curved SA $= 2\\pi rh$, total SA $= 2\\pi rh + 2\\pi r^2$.<br>• <b>Cone</b>: $V = \\frac{1}{3}\\pi r^2 h$, curved SA $= \\pi rl$ ($l$ = slant height, $l^2 = r^2 + h^2$).<br>• <b>Sphere</b>: $V = \\frac{4}{3}\\pi r^3$, SA $= 4\\pi r^2$.<br>• <b>Pyramid</b>: $V = \\frac{1}{3} \\times \\text{base area} \\times h$.<br><br><b>Key Skills</b><br>• Find volume and surface area of compound solids (e.g. hemisphere on cylinder).<br>• Find missing dimensions given volume or surface area.<br>• Use Pythagoras to find slant height of a cone.<br><br><b>Exam Tip</b><br>Formulae for cone, sphere, and pyramid are given on the formula sheet — but practise using them.","content_zh":"<b>知识回顾</b><br>• 长方体 $V = lwh$。棱柱 $V = 截面积 \\times 长$。<br>• 圆柱 $V = \\pi r^2 h$。圆锥 $V = \\frac{1}{3}\\pi r^2 h$。<br>• 球 $V = \\frac{4}{3}\\pi r^3$，$SA = 4\\pi r^2$。<br>• 棱锥 $V = \\frac{1}{3} \\times 底面积 \\times h$。<br><br><b>考试技巧</b><br>锥、球、棱锥公式在考卷公式页上给出——但要熟练使用。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.4', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>A solid is made from a cylinder (radius 5 cm, height 10 cm) with a hemisphere on top. Find the total volume and total surface area.<br><br><b>Solution:</b><br><b>Volume:</b><br>Cylinder: $\\pi \\times 25 \\times 10 = 250\\pi$<br>Hemisphere: $\\frac{1}{2} \\times \\frac{4}{3}\\pi \\times 125 = \\frac{250\\pi}{3}$<br>Total $= 250\\pi + \\frac{250\\pi}{3} = \\frac{1000\\pi}{3} = 1047\\text{ cm}^3$<br><br><b>Surface area:</b><br>Cylinder curved: $2\\pi \\times 5 \\times 10 = 100\\pi$<br>Base circle: $\\pi \\times 25 = 25\\pi$<br>Hemisphere curved: $2\\pi \\times 25 = 50\\pi$<br>Total $= 100\\pi + 25\\pi + 50\\pi = 175\\pi = 550\\text{ cm}^2$<br><br><b>Watch Out:</b> No top circle on the cylinder (hemisphere covers it) and no flat face on the hemisphere.","content_zh":"<b>经典例题</b> [5 分]<br>圆柱（半径 5 cm，高 10 cm）顶部加半球。求总体积和总表面积。<br><br><b>体积：</b>圆柱 $250\\pi$ + 半球 $\\frac{250\\pi}{3}$ = $\\frac{1000\\pi}{3} = 1047\\text{ cm}^3$<br><br><b>表面积：</b>圆柱侧面 $100\\pi$ + 底面 $25\\pi$ + 半球曲面 $50\\pi$ = $175\\pi = 550\\text{ cm}^2$<br>注意：圆柱顶部和半球底面不计！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.5', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Compound shapes</b> combine two or more basic shapes.<br>• Split the shape into rectangles, triangles, circles, trapeziums, etc.<br>• <b>Addition method</b>: area of whole = sum of parts.<br>• <b>Subtraction method</b>: area of whole shape minus removed sections.<br><br><b>Key Skills</b><br>• Find unknown dimensions from the given information.<br>• Calculate perimeters of compound shapes — only count <b>outer</b> edges.<br>• Solve problems combining 2D and 3D compound shapes.<br><br><b>Exam Tip</b><br>Sketch and label each sub-shape separately. This makes it easier to identify all dimensions.","content_zh":"<b>知识回顾</b><br>• <b>组合图形</b>：由多个基本图形组合。<br>• 加法：总面积 = 各部分之和。减法：整体 - 去除部分。<br>• 周长只算<b>外边缘</b>。<br><br><b>考试技巧</b><br>把每个子图形单独画出来标尺寸，更容易识别。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '5.5', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>An L-shaped room is 10 m by 8 m with a 4 m by 3 m rectangle removed from one corner. Find the area and perimeter.<br><br><b>Solution:</b><br>Area $= (10 \\times 8) - (4 \\times 3) = 80 - 12 = 68\\text{ m}^2$<br>Perimeter: trace the outside: $10 + 8 + 6 + 3 + 4 + 5 = 36$ m<br>(or $10 + 8 + (10-4) + 3 + 4 + (8-3) = 36$ m)<br><br><b>Exam Tip:</b> For perimeter, trace around the outside of the shape to make sure you count every edge.","content_zh":"<b>经典例题</b> [4 分]<br>L 形房间 10 m × 8 m，一个角去掉 4 m × 3 m 的矩形。求面积和周长。<br><br><b>解答：</b>面积 $= 80 - 12 = 68\\text{ m}^2$<br>周长：$10 + 8 + 6 + 3 + 4 + 5 = 36$ m"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.1', 'knowledge', '{"content":"<b>Recap</b><br>• In a right-angled triangle: $a^2 + b^2 = c^2$ where $c$ is the <b>hypotenuse</b> (longest side, opposite the right angle).<br>• To find the hypotenuse: $c = \\sqrt{a^2 + b^2}$.<br>• To find a shorter side: $a = \\sqrt{c^2 - b^2}$.<br><br><b>Key Skills</b><br>• Apply Pythagoras in 2D problems (distances, diagonals).<br>• <b>3D Pythagoras</b> (Extended): find the space diagonal $d = \\sqrt{l^2 + w^2 + h^2}$.<br>• Use Pythagoras to check if a triangle is right-angled: if $a^2 + b^2 = c^2$, yes.<br><br><b>Watch Out!</b><br>The hypotenuse is always opposite the right angle. Always identify it first before applying the theorem.","content_zh":"<b>知识回顾</b><br>• 直角三角形：$a^2 + b^2 = c^2$（$c$ 为斜边）。<br>• 求斜边：$c = \\sqrt{a^2 + b^2}$。求直角边：$a = \\sqrt{c^2 - b^2}$。<br>• 3D 勾股（Extended）：空间对角线 $d = \\sqrt{l^2 + w^2 + h^2}$。<br><br><b>注意！</b>斜边始终对着直角，先找到它再套公式。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>Find the hypotenuse of a right triangle with legs 6 cm and 8 cm.<br><br><b>Solution:</b><br>$c = \\sqrt{6^2 + 8^2} = \\sqrt{36 + 64} = \\sqrt{100} = 10$ cm<br><br><b>Worked Example 2</b> (Extended) [3 marks]<br>A cuboid is $3 \\times 4 \\times 12$. Find the space diagonal.<br><br><b>Solution:</b><br>$d = \\sqrt{3^2 + 4^2 + 12^2} = \\sqrt{9 + 16 + 144} = \\sqrt{169} = 13$","content_zh":"<b>经典例题 1</b> [2 分]<br>直角边 6 cm 和 8 cm，求斜边。<br><b>解答：</b>$\\sqrt{100} = 10$ cm<br><br><b>经典例题 2</b>（Extended）[3 分]<br>长方体 $3 \\times 4 \\times 12$，求空间对角线。<br><b>解答：</b>$\\sqrt{169} = 13$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>SOHCAHTOA</b>:<br>&nbsp;&nbsp;$\\sin\\theta = \\frac{\\text{Opposite}}{\\text{Hypotenuse}}$<br>&nbsp;&nbsp;$\\cos\\theta = \\frac{\\text{Adjacent}}{\\text{Hypotenuse}}$<br>&nbsp;&nbsp;$\\tan\\theta = \\frac{\\text{Opposite}}{\\text{Adjacent}}$<br><br><b>Key Skills</b><br>• Find a missing side: identify which ratio involves the known side and the unknown side.<br>• Find a missing angle: use the inverse function ($\\sin^{-1}$, $\\cos^{-1}$, $\\tan^{-1}$).<br>• <b>Angle of elevation</b>: looking UP from horizontal. <b>Angle of depression</b>: looking DOWN from horizontal.<br><br><b>Exam Tip</b><br>Label the sides O, A, H relative to the angle you are using. Then choose the correct ratio.","content_zh":"<b>知识回顾</b><br>• <b>SOHCAHTOA</b>：$\\sin = \\frac{对}{斜}$, $\\cos = \\frac{邻}{斜}$, $\\tan = \\frac{对}{邻}$。<br>• 求边：选包含已知边和未知边的比。<br>• 求角：用反函数 $\\sin^{-1}, \\cos^{-1}, \\tan^{-1}$。<br>• 仰角：从水平向上看。俯角：从水平向下看。<br><br><b>考试技巧</b><br>先标 O, A, H（相对于所用角），再选正确比。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.2', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>From the top of a 25 m cliff, the angle of depression to a boat is $32°$. Find the horizontal distance from the base of the cliff to the boat.<br><br><b>Solution:</b><br>The angle of depression from top = angle of elevation from boat = $32°$.<br>$\\tan 32° = \\frac{25}{d}$ → $d = \\frac{25}{\\tan 32°} = \\frac{25}{0.6249} = 40.0$ m<br><br><b>Exam Tip:</b> Draw a clear diagram. Angle of depression from the top equals the angle of elevation from the bottom (alternate angles).","content_zh":"<b>经典例题</b> [4 分]<br>25 m 高的悬崖顶部，俯角 $32°$ 看到船。求船到崖底的水平距离。<br><br><b>解答：</b>$\\tan 32° = \\frac{25}{d}$，$d = \\frac{25}{\\tan 32°} = 40.0$ m"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.3', 'knowledge', '{"content":"<b>Recap</b><br>You must know these exact values (no calculator):<br><br>| Angle | $\\sin$ | $\\cos$ | $\\tan$ |<br>| $0°$ | $0$ | $1$ | $0$ |<br>| $30°$ | $\\frac{1}{2}$ | $\\frac{\\sqrt{3}}{2}$ | $\\frac{1}{\\sqrt{3}}$ |<br>| $45°$ | $\\frac{\\sqrt{2}}{2}$ | $\\frac{\\sqrt{2}}{2}$ | $1$ |<br>| $60°$ | $\\frac{\\sqrt{3}}{2}$ | $\\frac{1}{2}$ | $\\sqrt{3}$ |<br>| $90°$ | $1$ | $0$ | undefined |<br><br><b>Key Skills</b><br>• Derive values from the 45-45-90 triangle (sides $1, 1, \\sqrt{2}$) and 30-60-90 triangle (sides $1, \\sqrt{3}, 2$).<br>• Use exact values in calculations without a calculator.","content_zh":"<b>知识回顾</b><br>必须记住（不用计算器）：<br>• $\\sin 30° = \\frac{1}{2}$, $\\cos 30° = \\frac{\\sqrt{3}}{2}$, $\\tan 30° = \\frac{1}{\\sqrt{3}}$<br>• $\\sin 45° = \\cos 45° = \\frac{\\sqrt{2}}{2}$, $\\tan 45° = 1$<br>• $\\sin 60° = \\frac{\\sqrt{3}}{2}$, $\\cos 60° = \\frac{1}{2}$, $\\tan 60° = \\sqrt{3}$<br><br>来源：45-45-90 三角形（边 $1, 1, \\sqrt{2}$）和 30-60-90 三角形（边 $1, \\sqrt{3}, 2$）。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.3', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Without a calculator, find the exact value of $\\frac{\\sin 60°}{\\cos 30°} + \\tan 45°$.<br><br><b>Solution:</b><br>$\\sin 60° = \\frac{\\sqrt{3}}{2}$, $\\cos 30° = \\frac{\\sqrt{3}}{2}$, $\\tan 45° = 1$<br>$\\frac{\\frac{\\sqrt{3}}{2}}{\\frac{\\sqrt{3}}{2}} + 1 = 1 + 1 = 2$<br><br><b>Worked Example 2</b> [2 marks]<br>An equilateral triangle has side 4 cm. Find the exact area.<br><br><b>Solution:</b><br>Height $= 4\\sin 60° = 4 \\times \\frac{\\sqrt{3}}{2} = 2\\sqrt{3}$<br>Area $= \\frac{1}{2} \\times 4 \\times 2\\sqrt{3} = 4\\sqrt{3}\\text{ cm}^2$","content_zh":"<b>经典例题</b> [3 分]<br>不用计算器求 $\\frac{\\sin 60°}{\\cos 30°} + \\tan 45°$ 的精确值。<br><br><b>解答：</b>$\\frac{\\frac{\\sqrt{3}}{2}}{\\frac{\\sqrt{3}}{2}} + 1 = 2$<br><br><b>经典例题 2</b> [2 分]<br>等边三角形边长 4 cm，求精确面积。<br><b>解答：</b>高 $= 2\\sqrt{3}$，面积 $= 4\\sqrt{3}\\text{ cm}^2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.4', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Sine curve</b> $y = \\sin x$: period $360°$, amplitude 1, passes through origin.<br>• <b>Cosine curve</b> $y = \\cos x$: period $360°$, amplitude 1, starts at $(0, 1)$.<br>• <b>Tangent curve</b> $y = \\tan x$: period $180°$, has vertical asymptotes at $90°, 270°$, etc.<br><br><b>Key Skills</b><br>• Sketch trig graphs for $0° \\leq x \\leq 360°$ (or beyond).<br>• Use symmetry of trig graphs to find multiple solutions: e.g. if $\\sin x = 0.5$, then $x = 30°$ or $x = 150°$.<br>• Solve equations like $\\sin x = k$ in a given range.<br><br><b>Exam Tip</b><br>Sketch the graph to see how many solutions exist in the given range. CAST diagram helps determine signs in each quadrant.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• 正弦 $y = \\sin x$：周期 $360°$，振幅 1，过原点。<br>• 余弦 $y = \\cos x$：周期 $360°$，振幅 1，从 $(0,1)$ 开始。<br>• 正切 $y = \\tan x$：周期 $180°$，有垂直渐近线。<br><br><b>关键技巧</b><br>利用图形对称性找多个解。CAST 图判定各象限正负。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.4', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Solve $\\sin x = 0.6$ for $0° \\leq x \\leq 360°$.<br><br><b>Solution:</b><br>$x = \\sin^{-1}(0.6) = 36.87°$<br>Sine is also positive in Q2: $x = 180° - 36.87° = 143.13°$<br>$x = 36.9°$ or $x = 143.1°$ (1 d.p.)<br><br><b>Exam Tip:</b> For $\\sin x = k$ (positive): solutions are $x$ and $180° - x$. For $\\cos x = k$ (positive): solutions are $x$ and $360° - x$.","content_zh":"<b>经典例题</b> [3 分]<br>在 $0° \\leq x \\leq 360°$ 范围内解 $\\sin x = 0.6$。<br><br><b>解答：</b>$x = 36.9°$（Q1）或 $x = 180° - 36.9° = 143.1°$（Q2）"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.5', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Sine Rule</b><br>$\\frac{a}{\\sin A} = \\frac{b}{\\sin B} = \\frac{c}{\\sin C}$<br>Use when you have: a side and its opposite angle PLUS one other piece.<br><br><b>Cosine Rule</b><br>• Finding a side: $a^2 = b^2 + c^2 - 2bc\\cos A$<br>• Finding an angle: $\\cos A = \\frac{b^2 + c^2 - a^2}{2bc}$<br>Use when you have: SAS (two sides + included angle) or SSS (three sides).<br><br><b>Area Formula</b><br>$A = \\frac{1}{2}ab\\sin C$<br><br><b>Watch Out!</b><br>The <b>ambiguous case</b> of the sine rule: when finding an angle, there may be two possible answers (acute and obtuse). Check if the obtuse answer is valid in context.","content_zh":"<b>仅 Extended</b><br><br><b>正弦定则</b>：$\\frac{a}{\\sin A} = \\frac{b}{\\sin B}$（有一组对边对角时使用）<br><br><b>余弦定则</b>：$a^2 = b^2 + c^2 - 2bc\\cos A$（SAS 或 SSS 时使用）<br>求角：$\\cos A = \\frac{b^2 + c^2 - a^2}{2bc}$<br><br><b>面积</b>：$A = \\frac{1}{2}ab\\sin C$<br><br><b>注意！</b>正弦定则的<b>歧义情况</b>：求角时可能有两个解（锐角和钝角）。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.5', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>In $\\triangle ABC$: $A = 40°$, $B = 75°$, $a = 10$ cm. Find side $b$.<br><br><b>Solution:</b><br>$\\frac{10}{\\sin 40°} = \\frac{b}{\\sin 75°}$<br>$b = \\frac{10 \\sin 75°}{\\sin 40°} = \\frac{10 \\times 0.9659}{0.6428} = 15.0$ cm<br><br><b>Worked Example 2</b> [4 marks]<br>In $\\triangle PQR$: $p = 7$, $q = 9$, $r = 5$. Find angle $Q$.<br><br><b>Solution:</b><br>$\\cos Q = \\frac{7^2 + 5^2 - 9^2}{2 \\times 7 \\times 5} = \\frac{49 + 25 - 81}{70} = \\frac{-7}{70} = -0.1$<br>$Q = \\cos^{-1}(-0.1) = 95.7°$","content_zh":"<b>经典例题 1</b> [3 分]<br>$A = 40°, B = 75°, a = 10$。求 $b$。<br><br><b>解答：</b>$b = \\frac{10\\sin 75°}{\\sin 40°} = 15.0$ cm<br><br><b>经典例题 2</b> [4 分]<br>$p = 7, q = 9, r = 5$。求角 $Q$。<br><br><b>解答：</b>$\\cos Q = \\frac{-7}{70} = -0.1$，$Q = 95.7°$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.6', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• In 3D problems, identify <b>right-angled triangles</b> within the solid.<br>• Apply <b>Pythagoras</b> and <b>SOHCAHTOA</b> to these 2D cross-sections.<br>• Common 3D shapes: cuboid, pyramid, wedge, cone.<br><br><b>Key Skills</b><br>• Find the <b>angle between a line and a plane</b>: drop a perpendicular from the point to the plane, identify the right triangle.<br>• Find the <b>angle between two planes</b>: find the line where they intersect, then draw perpendiculars in each plane to this line.<br>• Usually requires <b>two steps</b>: first find a length (using Pythagoras), then an angle (using trig).<br><br><b>Exam Tip</b><br>Draw a clear 2D right triangle extracted from the 3D shape. Label all known and unknown sides/angles.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• 3D 问题中找出立体内的直角三角形。<br>• 用勾股定理和三角比在 2D 截面上求解。<br><br><b>关键技巧</b><br>• 线面角：从点作垂线到平面，找直角三角形。<br>• 面面角：找交线，在各面上作垂线。<br>• 通常分两步：先用勾股求长度，再用三角比求角。<br><br><b>考试技巧</b><br>从 3D 中抽出 2D 直角三角形，清晰标注。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '6.6', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>A cuboid has dimensions $8 \\times 6 \\times 4$ cm. Find the angle between the space diagonal $AG$ and the base $ABCD$.<br><br><b>Solution:</b><br>Step 1: Find base diagonal $AC = \\sqrt{8^2 + 6^2} = \\sqrt{100} = 10$ cm.<br>Step 2: The space diagonal $AG$ goes from $A$ at the base to $G$ at the top. The right triangle has:<br>• Base $= AC = 10$ cm (along the base)<br>• Height $= CG = 4$ cm (vertical edge)<br>$\\tan\\theta = \\frac{4}{10} = 0.4$<br>$\\theta = \\tan^{-1}(0.4) = 21.8°$<br><br><b>Exam Tip:</b> Always identify which plane and which line. The angle is measured AT the base.","content_zh":"<b>经典例题</b> [5 分]<br>长方体 $8 \\times 6 \\times 4$ cm。求空间对角线 $AG$ 与底面 $ABCD$ 的夹角。<br><br><b>解答：</b>底面对角线 $AC = \\sqrt{100} = 10$<br>$\\tan\\theta = \\frac{4}{10}$，$\\theta = 21.8°$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '5.1', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>vector</b> has magnitude (size) and direction. Written as $\\vec{AB}$, $\\mathbf{a}$, or $\\binom{x}{y}$.<br>• A <b>scalar</b> has magnitude only (just a number).<br>• <b>Column vector</b>: $\\binom{3}{-2}$ means 3 right and 2 down.<br>• <b>Addition</b>: $\\binom{a}{b} + \\binom{c}{d} = \\binom{a+c}{b+d}$.<br>• <b>Scalar multiplication</b>: $k\\binom{a}{b} = \\binom{ka}{kb}$.<br>• <b>Magnitude</b>: $|\\mathbf{a}| = \\sqrt{x^2 + y^2}$.<br>• <b>Parallel vectors</b>: one is a scalar multiple of the other.<br>• $-\\mathbf{a}$ reverses direction. $\\vec{BA} = -\\vec{AB}$.<br><br><b>Higher Only</b><br>• <b>Vector geometry proofs</b>: express vectors in terms of $\\mathbf{a}$ and $\\mathbf{b}$.<br>• To prove points are collinear, show one vector is a scalar multiple of another.<br>• Midpoint: $\\vec{OM} = \\frac{1}{2}(\\vec{OA} + \\vec{OB})$.<br><br><b>Exam Tip</b><br>When finding a route, go via known points: $\\vec{AC} = \\vec{AB} + \\vec{BC}$.","content_zh":"<b>知识回顾</b><br>• <b>向量</b>有大小和方向。列向量 $\\binom{3}{-2}$：右 3 下 2。<br>• 加法：$\\binom{a}{b} + \\binom{c}{d} = \\binom{a+c}{b+d}$。<br>• 标量乘法：$k\\binom{a}{b} = \\binom{ka}{kb}$。模：$|\\mathbf{a}| = \\sqrt{x^2+y^2}$。<br>• 平行向量：一个是另一个的标量倍。$-\\mathbf{a}$ 反向。<br><br><b>仅 Higher</b><br>• 向量几何证明：用 $\\mathbf{a}, \\mathbf{b}$ 表示向量。<br>• 共线：一个向量是另一个的标量倍。<br><br><b>考试技巧</b>经过已知点找路径：$\\vec{AC} = \\vec{AB} + \\vec{BC}$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '5.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>$\\mathbf{a} = \\binom{3}{-1}$ and $\\mathbf{b} = \\binom{-2}{4}$. Find $2\\mathbf{a} + \\mathbf{b}$.<br><br><b>Solution:</b><br>$2\\mathbf{a} + \\mathbf{b} = \\binom{6}{-2} + \\binom{-2}{4} = \\binom{4}{2}$<br><br><b>Worked Example 2</b> (Higher) [4 marks]<br>$\\vec{OA} = \\mathbf{a}$, $\\vec{OB} = \\mathbf{b}$. $M$ is the midpoint of $AB$. Find $\\vec{OM}$.<br><br><b>Solution:</b><br>$\\vec{AB} = \\mathbf{b} - \\mathbf{a}$<br>$\\vec{AM} = \\frac{1}{2}\\vec{AB} = \\frac{1}{2}(\\mathbf{b} - \\mathbf{a})$<br>$\\vec{OM} = \\vec{OA} + \\vec{AM} = \\mathbf{a} + \\frac{1}{2}(\\mathbf{b} - \\mathbf{a}) = \\frac{1}{2}\\mathbf{a} + \\frac{1}{2}\\mathbf{b} = \\frac{1}{2}(\\mathbf{a} + \\mathbf{b})$","content_zh":"<b>经典例题 1</b> [2 分]<br>$\\mathbf{a} = \\binom{3}{-1}$，$\\mathbf{b} = \\binom{-2}{4}$。求 $2\\mathbf{a} + \\mathbf{b}$。<br><br><b>解答：</b>$\\binom{4}{2}$<br><br><b>经典例题 2</b>（Higher）[4 分]<br>$\\vec{OA} = \\mathbf{a}$，$\\vec{OB} = \\mathbf{b}$，$M$ 为 $AB$ 中点。求 $\\vec{OM}$。<br><br><b>解答：</b>$\\vec{OM} = \\frac{1}{2}(\\mathbf{a} + \\mathbf{b})$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '5.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Translation</b>: slide by vector $\\binom{a}{b}$. No change in size, shape, or orientation.<br>• <b>Reflection</b>: flip in a mirror line. Describe with the <b>equation of the line</b>.<br>• <b>Rotation</b>: turn about a centre. Describe with <b>centre, angle, direction</b> (clockwise/anticlockwise).<br>• <b>Enlargement</b>: resize from a centre. Describe with <b>centre, scale factor</b>.<br>&nbsp;&nbsp;$k > 1$: bigger. $0 < k < 1$: smaller. $k < 0$: inverted (Higher).<br><br><b>Key Skills</b><br>• Perform each transformation on a shape on a coordinate grid.<br>• <b>Describe</b> a given transformation fully (must include all required details).<br><br><b>Watch Out!</b><br>\"Describe fully\" means you need ALL the details. For rotation: centre + angle + direction. For enlargement: centre + scale factor. Missing any one loses marks.","content_zh":"<b>知识回顾</b><br>• <b>平移</b>：用向量 $\\binom{a}{b}$ 描述。大小、形状、方向不变。<br>• <b>反射</b>：沿镜像线翻转。需说明线的方程。<br>• <b>旋转</b>：需说明<b>中心、角度、方向</b>。<br>• <b>放大</b>：需说明<b>中心、缩放因子</b>。$k > 1$ 放大，$0 < k < 1$ 缩小，$k < 0$ 翻转。<br><br><b>注意！</b>\"Describe fully\"必须包含所有细节，缺一扣分。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '5.2', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Triangle $A$ has vertices $(1,1)$, $(3,1)$, $(1,4)$. It is rotated $90°$ clockwise about the origin. Find the image vertices.<br><br><b>Solution:</b><br>$90°$ clockwise: $(x, y) \\rightarrow (y, -x)$<br>$(1,1) \\rightarrow (1,-1)$, $(3,1) \\rightarrow (1,-3)$, $(1,4) \\rightarrow (4,-1)$<br><br><b>Worked Example 2</b> [3 marks]<br>Describe fully the single transformation that maps triangle $P$ at $(2,3), (6,3), (6,5)$ to triangle $Q$ at $(4,6), (12,6), (12,10)$.<br><br><b>Solution:</b><br><b>Enlargement</b>, scale factor <b>2</b>, centre <b>$(0, 0)$</b>.<br>(Each coordinate is doubled, so centre is origin.)","content_zh":"<b>经典例题 1</b> [3 分]<br>三角形顶点 $(1,1), (3,1), (1,4)$，绕原点顺时针旋转 $90°$。求像。<br><br><b>解答：</b>$(x,y) \\rightarrow (y,-x)$：$(1,-1), (1,-3), (4,-1)$<br><br><b>经典例题 2</b> [3 分]<br>描述变换：$P(2,3),(6,3),(6,5)$ → $Q(4,6),(12,6),(12,10)$。<br><br><b>解答：</b>以原点为中心、缩放因子 2 的<b>放大</b>。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.1', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Bar chart</b>: bars for categorical data. Gaps between bars.<br>• <b>Pictogram</b>: pictures represent data. Include a key.<br>• <b>Pie chart</b>: angles proportional to frequency. Total = $360°$.<br>• <b>Line graph</b>: for time series data. Plot points and join.<br>• <b>Stem-and-leaf diagram</b>: ordered raw data display. Must include a key.<br>• <b>Frequency polygon</b>: plot midpoints of classes, join with straight lines.<br>• <b>Scatter diagram</b>: show relationship between two variables. Describe <b>correlation</b> (positive, negative, none).<br><br><b>Higher Only</b><br>• <b>Histogram</b>: frequency density $= \\frac{\\text{frequency}}{\\text{class width}}$. <b>No gaps</b> between bars.<br>• <b>Cumulative frequency</b>: running total plotted at upper class boundary. S-shaped curve.<br>• <b>Box plot</b> (box-and-whisker): min, LQ, median, UQ, max.<br><br><b>Exam Tip</b><br>In histograms, the <b>area</b> of each bar represents frequency, not the height.","content_zh":"<b>知识回顾</b><br>• 柱状图：分类数据，柱间有间隙。饼图：角度 ∝ 频率，总 $360°$。<br>• 茎叶图：有序原始数据，须有图例。频率折线图：用组中值。<br>• 散点图：两变量关系，描述相关性。<br><br><b>仅 Higher</b><br>• 直方图：频率密度 = $\\frac{频率}{组距}$，柱间无间隙。<b>面积</b>代表频率。<br>• 累积频率曲线：在上组界处画点。箱线图：最小值, LQ, 中位数, UQ, 最大值。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.1', 'examples', '{"content":"<b>Worked Example 1</b> [2 marks]<br>40 students took a test. Draw a pie chart angle for the 15 who scored A.<br><br><b>Solution:</b><br>Angle $= \\frac{15}{40} \\times 360° = 135°$<br><br><b>Worked Example 2</b> (Higher) [3 marks]<br>A grouped frequency table has class $10 \\leq x < 25$ with frequency 30. Find the frequency density and bar height for the histogram.<br><br><b>Solution:</b><br>Class width $= 25 - 10 = 15$<br>Frequency density $= \\frac{30}{15} = 2$<br>The bar has height 2 and width from 10 to 25.","content_zh":"<b>经典例题 1</b> [2 分]<br>40 名学生中 15 人得 A，画饼图角度。<br><b>解答：</b>$\\frac{15}{40} \\times 360° = 135°$<br><br><b>经典例题 2</b>（Higher）[3 分]<br>分组频率表：$10 \\leq x < 25$，频率 30。求频率密度。<br><b>解答：</b>组距 15，频率密度 $= \\frac{30}{15} = 2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Mean</b> $= \\frac{\\text{sum of values}}{\\text{number of values}}$. For grouped data: $\\bar{x} = \\frac{\\sum fx}{\\sum f}$ (use midpoints).<br>• <b>Median</b>: middle value when data is ordered. Position: $\\frac{n+1}{2}$.<br>• <b>Mode</b>: most common value. Can have no mode or multiple modes.<br>• <b>Range</b> $=$ largest $-$ smallest.<br><br><b>Higher Only</b><br>• <b>Interquartile range (IQR)</b> $= Q_3 - Q_1$. Measures the spread of the middle 50%.<br>• From cumulative frequency: median at $\\frac{n}{2}$, $Q_1$ at $\\frac{n}{4}$, $Q_3$ at $\\frac{3n}{4}$.<br>• Compare distributions using an average (mean or median) AND a measure of spread (range or IQR).<br><br><b>Exam Tip</b><br>For grouped data, the mean uses midpoints so it is an <b>estimate</b>. Say \"estimated mean\".","content_zh":"<b>知识回顾</b><br>• 平均值 $= \\frac{总和}{个数}$。分组数据：$\\bar{x} = \\frac{\\sum fx}{\\sum f}$（用组中值）。<br>• 中位数：有序数据中间值。众数：出现最多。<br>• 极差 = 最大 - 最小。<br><br><b>仅 Higher</b><br>• IQR $= Q_3 - Q_1$。累积频率求：中位数在 $\\frac{n}{2}$，$Q_1$ 在 $\\frac{n}{4}$，$Q_3$ 在 $\\frac{3n}{4}$。<br><br><b>考试技巧</b><br>分组数据求的是\"估计平均值\"（用组中值）。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.2', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Five students scored: 45, 62, 58, 71, 54. Find the mean, median, and range.<br><br><b>Solution:</b><br>Mean $= \\frac{45+62+58+71+54}{5} = \\frac{290}{5} = 58$<br>Ordered: 45, 54, 58, 62, 71. Median $= 58$<br>Range $= 71 - 45 = 26$<br><br><b>Worked Example 2</b> (Higher) [4 marks]<br>From a cumulative frequency graph, $n = 80$. Read off the median and IQR.<br><br><b>Solution:</b><br>Median at $\\frac{80}{2} = 40$th value. Read across: median $= 52$.<br>$Q_1$ at 20th value $= 43$. $Q_3$ at 60th value $= 64$.<br>IQR $= 64 - 43 = 21$.","content_zh":"<b>经典例题 1</b> [3 分]<br>五人成绩 45, 62, 58, 71, 54，求平均值、中位数、极差。<br><br><b>解答：</b>均值 58，中位数 58，极差 26<br><br><b>经典例题 2</b>（Higher）[4 分]<br>累积频率图 $n = 80$。<br><br><b>解答：</b>中位数在第 40 → 52。$Q_1 = 43, Q_3 = 64$。IQR $= 21$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.3', 'knowledge', '{"content":"<b>Recap</b><br>• $P(\\text{event}) = \\frac{\\text{favourable outcomes}}{\\text{total outcomes}}$. Always $0 \\leq P \\leq 1$.<br>• $P(\\text{not } A) = 1 - P(A)$.<br>• <b>Sample space</b>: list of all outcomes. Use tables or lists for combined events.<br>• <b>Relative frequency</b> $= \\frac{\\text{number of times event occurs}}{\\text{total trials}}$. Better estimate with more trials.<br><br><b>Key Skills</b><br>• <b>Tree diagrams</b>: multiply along branches (AND), add between branches (OR).<br>• <b>Independent events</b>: $P(A \\text{ and } B) = P(A) \\times P(B)$.<br>• <b>Mutually exclusive</b>: $P(A \\text{ or } B) = P(A) + P(B)$.<br><br><b>Higher Only</b><br>• <b>Conditional probability</b>: $P(A | B) = \\frac{P(A \\cap B)}{P(B)}$.<br>• <b>Without replacement</b>: probabilities change on second pick.<br>• <b>Venn diagrams</b>: $P(A \\cup B) = P(A) + P(B) - P(A \\cap B)$.<br><br><b>Watch Out!</b><br>\"At least one\" is easiest solved as $1 - P(\\text{none})$.","content_zh":"<b>知识回顾</b><br>• $P = \\frac{有利结果}{总结果}$，$0 \\leq P \\leq 1$。$P(\\bar{A}) = 1 - P(A)$。<br>• 树形图：沿分支乘（和），不同分支加（或）。<br>• 独立事件：$P(A \\cap B) = P(A) \\times P(B)$。互斥：$P(A \\cup B) = P(A) + P(B)$。<br><br><b>仅 Higher</b><br>• 条件概率：$P(A|B) = \\frac{P(A \\cap B)}{P(B)}$。<br>• 不放回：第二次概率改变。<br>• 韦恩图：$P(A \\cup B) = P(A) + P(B) - P(A \\cap B)$。<br><br><b>注意！</b>\"至少一个\"最简单方法：$1 - P(\\text{一个也没有})$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('edexcel', '6.3', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>A bag has 5 red and 3 blue balls. One is picked at random, not replaced, then another is picked. Find the probability both are red.<br><br><b>Solution:</b><br>$P(\\text{1st red}) = \\frac{5}{8}$<br>$P(\\text{2nd red} | \\text{1st red}) = \\frac{4}{7}$<br>$P(\\text{both red}) = \\frac{5}{8} \\times \\frac{4}{7} = \\frac{20}{56} = \\frac{5}{14}$<br><br><b>Worked Example 2</b> (Higher) [3 marks]<br>$P(A) = 0.6$, $P(B) = 0.3$, $P(A \\cap B) = 0.15$. Find $P(A \\cup B)$ and determine if $A$ and $B$ are independent.<br><br><b>Solution:</b><br>$P(A \\cup B) = 0.6 + 0.3 - 0.15 = 0.75$<br>Check: $P(A) \\times P(B) = 0.18 \\neq 0.15$, so NOT independent.<br><br><b>Exam Tip:</b> Independent ⟺ $P(A \\cap B) = P(A) \\times P(B)$.","content_zh":"<b>经典例题 1</b> [3 分]<br>袋中 5 红 3 蓝，不放回取两个。求都是红色的概率。<br><br><b>解答：</b>$\\frac{5}{8} \\times \\frac{4}{7} = \\frac{5}{14}$<br><br><b>经典例题 2</b>（Higher）[3 分]<br>$P(A) = 0.6, P(B) = 0.3, P(A \\cap B) = 0.15$。判断是否独立。<br><br><b>解答：</b>$P(A \\cup B) = 0.75$。$P(A)P(B) = 0.18 \\neq 0.15$，不独立。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '7.1', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Translation</b>: every point moves by the same vector $\\binom{a}{b}$. Shape and size unchanged.<br>• <b>Reflection</b>: mirror image in a line. Give the <b>equation</b> of the mirror line (e.g. $y = x$, $x = 3$).<br>• <b>Rotation</b>: turn about a fixed point. Give <b>centre</b>, <b>angle</b>, and <b>direction</b> (clockwise/anticlockwise).<br>• <b>Enlargement</b>: scale from a centre. Give <b>centre</b> and <b>scale factor</b> $k$.<br>&nbsp;&nbsp;$k > 1$: larger. $0 < k < 1$: smaller. $k < 0$: inverted (Extended).<br><br><b>Extended Only</b><br>• <b>Shear</b>: shape distorted parallel to an invariant line. Shear factor $= \\frac{\\text{displacement}}{\\text{distance from invariant line}}$.<br>• <b>Stretch</b>: enlargement in one direction only. Perpendicular to an invariant line. Stretch factor $= \\frac{\\text{new distance}}{\\text{original distance}}$.<br>• <b>Transformation matrices</b> (2×2): rotation, reflection, enlargement, shear, stretch.<br><br><b>Exam Tip</b><br>\"Describe fully\" = name + all details. Miss the centre of rotation = lose a mark.","content_zh":"<b>知识回顾</b><br>• <b>平移</b>：向量 $\\binom{a}{b}$。<b>反射</b>：给出镜像线方程。<br>• <b>旋转</b>：给出中心、角度、方向。<b>放大</b>：给出中心和缩放因子。<br><br><b>仅 Extended</b><br>• <b>剪切</b>：沿不变线平行变形。剪切因子 = $\\frac{位移}{到不变线距离}$。<br>• <b>拉伸</b>：沿垂直于不变线方向缩放。<br>• 变换矩阵（2×2）。<br><br><b>考试技巧</b>\"Describe fully\"= 名称 + 所有细节。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '7.1', 'examples', '{"content":"<b>Worked Example 1</b> [3 marks]<br>Describe fully the single transformation that maps $A(1,2)$, $B(3,2)$, $C(3,4)$ to $A''(-2,1)$, $B''(-2,3)$, $C''(-4,3)$.<br><br><b>Solution:</b><br>$(x,y) \\rightarrow (-y, x)$: this is a <b>rotation</b>, $90°$ <b>anticlockwise</b>, centre <b>$(0,0)$</b>.<br><br><b>Worked Example 2</b> [2 marks]<br>Triangle $P$ is reflected in the line $y = -x$ to give triangle $Q$. Describe the single transformation from $P$ to $Q$.<br><br><b>Solution:</b><br><b>Reflection</b> in the line $y = -x$.","content_zh":"<b>经典例题 1</b> [3 分]<br>描述将 $(1,2),(3,2),(3,4)$ 映射到 $(-2,1),(-2,3),(-4,3)$ 的变换。<br><br><b>解答：</b>绕 $(0,0)$ <b>逆时针旋转 $90°$</b>。<br><br><b>经典例题 2</b> [2 分]<br>关于 $y = -x$ 的<b>反射</b>。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '7.2', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>vector</b> has magnitude and direction: $\\vec{AB}$, $\\mathbf{a}$, or $\\binom{x}{y}$.<br>• <b>Column vector</b> $\\binom{3}{-2}$: 3 right, 2 down.<br>• <b>Addition</b>: $\\binom{a}{b} + \\binom{c}{d} = \\binom{a+c}{b+d}$. <b>Subtraction</b>: $\\mathbf{a} - \\mathbf{b} = \\mathbf{a} + (-\\mathbf{b})$.<br>• <b>Scalar multiplication</b>: $k\\binom{a}{b} = \\binom{ka}{kb}$.<br>• $-\\mathbf{a}$ reverses direction. $\\vec{BA} = -\\vec{AB}$.<br>• <b>Equal vectors</b>: same magnitude AND direction (same column vector).<br>• <b>Parallel vectors</b>: one is a scalar multiple of the other.<br><br><b>Exam Tip</b><br>Vectors are not the same as coordinates! $\\binom{3}{4}$ is a movement, not a position.","content_zh":"<b>知识回顾</b><br>• 向量有大小和方向。列向量 $\\binom{3}{-2}$：右 3 下 2。<br>• 加法：分量相加。标量乘法：每个分量乘以标量。<br>• $-\\mathbf{a}$ 反向。$\\vec{BA} = -\\vec{AB}$。<br>• 相等向量：大小和方向都相同。平行向量：标量倍数关系。<br><br><b>考试技巧</b>向量是移动，不是位置！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '7.2', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>$\\mathbf{p} = \\binom{4}{-3}$, $\\mathbf{q} = \\binom{-1}{5}$. Find (a) $\\mathbf{p} + 2\\mathbf{q}$, (b) show $\\mathbf{p}$ and $\\binom{-8}{6}$ are parallel.<br><br><b>Solution:</b><br>(a) $\\mathbf{p} + 2\\mathbf{q} = \\binom{4}{-3} + \\binom{-2}{10} = \\binom{2}{7}$<br><br>(b) $\\binom{-8}{6} = -2\\binom{4}{-3} = -2\\mathbf{p}$, so they are parallel (scalar multiple).","content_zh":"<b>经典例题</b> [3 分]<br>$\\mathbf{p} = \\binom{4}{-3}$，$\\mathbf{q} = \\binom{-1}{5}$。<br><br>(a) $\\mathbf{p} + 2\\mathbf{q} = \\binom{2}{7}$<br>(b) $\\binom{-8}{6} = -2\\mathbf{p}$，故平行。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '7.3', 'knowledge', '{"content":"<b>Recap</b><br>• The <b>magnitude</b> (modulus) of $\\mathbf{a} = \\binom{x}{y}$ is $|\\mathbf{a}| = \\sqrt{x^2 + y^2}$.<br>• A <b>unit vector</b> has magnitude 1: $\\hat{\\mathbf{a}} = \\frac{\\mathbf{a}}{|\\mathbf{a}|}$.<br><br><b>Key Skills</b><br>• Calculate the magnitude of a vector.<br>• Find the distance between two points using $|\\vec{AB}|$.<br>• Compare vector magnitudes to determine which is longer.<br><br><b>Exam Tip</b><br>The magnitude is always positive. $|\\mathbf{a}|$ is just Pythagoras applied to the components.","content_zh":"<b>知识回顾</b><br>• 向量 $\\binom{x}{y}$ 的<b>模</b>：$|\\mathbf{a}| = \\sqrt{x^2 + y^2}$。<br>• 单位向量：$\\hat{\\mathbf{a}} = \\frac{\\mathbf{a}}{|\\mathbf{a}|}$，模为 1。<br><br><b>考试技巧</b>模始终为正，就是分量的勾股定理。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '7.3', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>$\\vec{AB} = \\binom{5}{-12}$. Find $|\\vec{AB}|$.<br><br><b>Solution:</b><br>$|\\vec{AB}| = \\sqrt{5^2 + (-12)^2} = \\sqrt{25 + 144} = \\sqrt{169} = 13$<br><br><b>Worked Example 2</b> [2 marks]<br>$\\mathbf{v} = \\binom{3}{4}$. Find the unit vector in the direction of $\\mathbf{v}$.<br><br><b>Solution:</b><br>$|\\mathbf{v}| = \\sqrt{9+16} = 5$. Unit vector $= \\frac{1}{5}\\binom{3}{4} = \\binom{0.6}{0.8}$","content_zh":"<b>经典例题</b> [3 分]<br>$\\vec{AB} = \\binom{5}{-12}$，求 $|\\vec{AB}|$。<br><b>解答：</b>$\\sqrt{169} = 13$<br><br><b>经典例题 2</b> [2 分]<br>$\\mathbf{v} = \\binom{3}{4}$，求单位向量。<br><b>解答：</b>$\\frac{1}{5}\\binom{3}{4} = \\binom{0.6}{0.8}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '7.4', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• Express position vectors and path vectors in terms of given vectors $\\mathbf{a}$ and $\\mathbf{b}$.<br>• <b>Route finding</b>: $\\vec{AC} = \\vec{AB} + \\vec{BC}$ (go via known points).<br>• <b>Midpoint</b>: $\\vec{OM} = \\frac{1}{2}(\\vec{OA} + \\vec{OB})$.<br>• A point dividing $AB$ in ratio $m:n$: $\\vec{OP} = \\frac{n\\vec{OA} + m\\vec{OB}}{m+n}$.<br><br><b>Key Skills</b><br>• Prove <b>collinearity</b>: show $\\vec{XY} = k\\vec{XZ}$ (one vector is scalar multiple of the other, sharing point $X$).<br>• Prove <b>parallel lines</b>: show $\\vec{PQ} = k\\vec{RS}$ (scalar multiple, no shared point).<br>• Prove a quadrilateral is a parallelogram: show opposite sides are equal vectors.<br><br><b>Exam Tip</b><br>Work systematically: define $\\vec{OA} = \\mathbf{a}$, $\\vec{OB} = \\mathbf{b}$, then express everything in terms of $\\mathbf{a}$ and $\\mathbf{b}$.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• 用 $\\mathbf{a}, \\mathbf{b}$ 表示位置向量和路径向量。<br>• 路径：$\\vec{AC} = \\vec{AB} + \\vec{BC}$。中点：$\\vec{OM} = \\frac{1}{2}(\\vec{OA} + \\vec{OB})$。<br><br><b>关键技巧</b><br>• 共线证明：$\\vec{XY} = k\\vec{XZ}$。<br>• 平行证明：$\\vec{PQ} = k\\vec{RS}$（无共点）。<br>• 平行四边形：对边向量相等。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '7.4', 'examples', '{"content":"<b>Worked Example</b> [5 marks]<br>$\\vec{OA} = \\mathbf{a}$, $\\vec{OB} = \\mathbf{b}$. $M$ is the midpoint of $OA$, $N$ is the midpoint of $OB$. Show that $MN$ is parallel to $AB$ and $MN = \\frac{1}{2}AB$.<br><br><b>Solution:</b><br>$\\vec{OM} = \\frac{1}{2}\\mathbf{a}$, $\\vec{ON} = \\frac{1}{2}\\mathbf{b}$<br>$\\vec{MN} = \\vec{MO} + \\vec{ON} = -\\frac{1}{2}\\mathbf{a} + \\frac{1}{2}\\mathbf{b} = \\frac{1}{2}(\\mathbf{b} - \\mathbf{a})$<br>$\\vec{AB} = \\mathbf{b} - \\mathbf{a}$<br>$\\vec{MN} = \\frac{1}{2}\\vec{AB}$<br>Since $\\vec{MN}$ is a scalar multiple of $\\vec{AB}$, they are <b>parallel</b>. Since the scalar is $\\frac{1}{2}$, $MN = \\frac{1}{2}AB$. QED.","content_zh":"<b>经典例题</b> [5 分]<br>$\\vec{OA} = \\mathbf{a}$, $\\vec{OB} = \\mathbf{b}$。$M$ 为 $OA$ 中点，$N$ 为 $OB$ 中点。证明 $MN \\parallel AB$ 且 $MN = \\frac{1}{2}AB$。<br><br><b>解答：</b>$\\vec{MN} = \\frac{1}{2}(\\mathbf{b} - \\mathbf{a}) = \\frac{1}{2}\\vec{AB}$<br>标量倍数关系 → 平行，系数 $\\frac{1}{2}$ → 长度为一半。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '8.1', 'knowledge', '{"content":"<b>Recap</b><br>• Probability measures how likely an event is: $0 \\leq P \\leq 1$.<br>• $P = 0$: impossible. $P = 1$: certain.<br>• $P(\\text{event}) = \\frac{\\text{number of favourable outcomes}}{\\text{total number of equally likely outcomes}}$.<br>• $P(A'') = 1 - P(A)$ where $A''$ means \"not $A$\".<br><br><b>Key Skills</b><br>• List outcomes systematically (sample space diagrams, two-way tables).<br>• Find probabilities from frequency tables.<br>• Express probability as fractions, decimals, or percentages.<br><br><b>Exam Tip</b><br>Always simplify fractions in your final answer unless told otherwise.","content_zh":"<b>知识回顾</b><br>• 概率 $0 \\leq P \\leq 1$。0 = 不可能，1 = 必然。<br>• $P = \\frac{有利结果数}{总等可能结果数}$。$P(A'') = 1 - P(A)$。<br><br><b>关键技巧</b><br>• 用样本空间图或两向表系统列出结果。<br><br><b>考试技巧</b>最终答案化简分数。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '8.1', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>A bag contains 4 red, 3 blue, and 5 green balls. A ball is picked at random. Find the probability it is (a) blue, (b) not green.<br><br><b>Solution:</b><br>Total $= 4 + 3 + 5 = 12$<br>(a) $P(\\text{blue}) = \\frac{3}{12} = \\frac{1}{4}$<br>(b) $P(\\text{not green}) = 1 - \\frac{5}{12} = \\frac{7}{12}$","content_zh":"<b>经典例题</b> [3 分]<br>袋中 4 红 3 蓝 5 绿，随机取一个。求 (a) 蓝色 (b) 不是绿色的概率。<br><br><b>解答：</b>总 12 个。(a) $\\frac{3}{12} = \\frac{1}{4}$ (b) $1 - \\frac{5}{12} = \\frac{7}{12}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '8.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Relative frequency</b> $= \\frac{\\text{number of times event occurs}}{\\text{total number of trials}}$.<br>• As the number of trials increases, relative frequency approaches the <b>theoretical probability</b>.<br>• <b>Expected frequency</b> $= P(\\text{event}) \\times \\text{number of trials}$.<br><br><b>Key Skills</b><br>• Estimate probability from experimental data.<br>• Compare experimental and theoretical probabilities.<br>• Calculate expected number of occurrences.<br><br><b>Exam Tip</b><br>\"Estimate the probability\" = use relative frequency. \"Calculate the probability\" = use equally likely outcomes.","content_zh":"<b>知识回顾</b><br>• <b>相对频率</b> = $\\frac{事件发生次数}{总试验次数}$。试验次数越多越接近理论概率。<br>• <b>期望频率</b> = $P \\times$ 试验次数。<br><br><b>考试技巧</b><br>\"估计概率\" = 用相对频率。\"计算概率\" = 用等可能结果。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '8.2', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>A biased coin is flipped 200 times and lands heads 118 times. (a) Estimate the probability of heads. (b) If flipped 500 times, how many heads are expected?<br><br><b>Solution:</b><br>(a) $P(H) \\approx \\frac{118}{200} = 0.59$<br>(b) Expected heads $= 0.59 \\times 500 = 295$","content_zh":"<b>经典例题</b> [3 分]<br>有偏硬币抛 200 次，正面 118 次。(a) 估计正面概率。(b) 抛 500 次预计几次正面。<br><br><b>解答：</b>(a) $0.59$ (b) $0.59 \\times 500 = 295$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '8.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>AND rule</b> (independent events): $P(A \\text{ and } B) = P(A) \\times P(B)$.<br>• <b>OR rule</b> (mutually exclusive): $P(A \\text{ or } B) = P(A) + P(B)$.<br>• <b>Tree diagrams</b>: multiply along branches (AND), add between branches (OR).<br><br><b>Key Skills</b><br>• Draw and use tree diagrams for two or more successive events.<br>• \"With replacement\" vs \"without replacement\": probabilities change in the second case.<br>• \"At least one\" = $1 - P(\\text{none})$.<br><br><b>Watch Out!</b><br>Check whether the events are \"with replacement\" or \"without replacement\". Without replacement means the second probability changes.","content_zh":"<b>知识回顾</b><br>• AND：$P(A \\cap B) = P(A) \\times P(B)$（独立）。OR：$P(A \\cup B) = P(A) + P(B)$（互斥）。<br>• 树形图：沿分支乘，不同分支加。<br>• 有放回 vs 无放回：无放回时第二次概率变化。<br>• \"至少一个\" = $1 - P$(一个也没有)。<br><br><b>注意！</b>先判断有放回还是无放回！"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '8.3', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>A bag has 6 red and 4 blue balls. Two are picked <b>without replacement</b>. Find $P$(both different colours).<br><br><b>Solution:</b><br>$P(\\text{RB}) = \\frac{6}{10} \\times \\frac{4}{9} = \\frac{24}{90}$<br>$P(\\text{BR}) = \\frac{4}{10} \\times \\frac{6}{9} = \\frac{24}{90}$<br>$P(\\text{different}) = \\frac{24}{90} + \\frac{24}{90} = \\frac{48}{90} = \\frac{8}{15}$<br><br><b>Alternative:</b> $P(\\text{different}) = 1 - P(\\text{same}) = 1 - \\frac{30+12}{90} = 1 - \\frac{42}{90} = \\frac{48}{90} = \\frac{8}{15}$","content_zh":"<b>经典例题</b> [4 分]<br>6 红 4 蓝，不放回取两个。求颜色不同的概率。<br><br><b>解答：</b>$P(RB) + P(BR) = \\frac{24}{90} + \\frac{24}{90} = \\frac{8}{15}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '8.4', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Conditional probability</b>: $P(A | B)$ = probability of $A$ given that $B$ has occurred.<br>• $P(A | B) = \\frac{P(A \\cap B)}{P(B)}$.<br>• In tree diagrams: \"without replacement\" naturally gives conditional probabilities (second branch changes).<br><br><b>Key Skills</b><br>• Use two-way tables or Venn diagrams to find conditional probabilities.<br>• <b>Venn diagrams</b>: $P(A \\cup B) = P(A) + P(B) - P(A \\cap B)$.<br>• Read $P(A | B)$ from a Venn diagram: focus on the $B$ circle, find the $A \\cap B$ portion.<br><br><b>Exam Tip</b><br>\"Given that\" always means conditional probability. The denominator is the \"given\" group.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• 条件概率：$P(A|B) = \\frac{P(A \\cap B)}{P(B)}$。<br>• 韦恩图：$P(A \\cup B) = P(A) + P(B) - P(A \\cap B)$。<br>• \"given that\" = 条件概率，分母是\"给定\"的那组。<br><br><b>考试技巧</b>\"Given that\"总意味着条件概率。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '8.4', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>In a class of 30: 18 play football, 12 play tennis, 5 play both. A student is chosen at random. Find (a) $P$(football or tennis), (b) $P$(tennis | football).<br><br><b>Solution:</b><br>(a) $P(F \\cup T) = \\frac{18 + 12 - 5}{30} = \\frac{25}{30} = \\frac{5}{6}$<br><br>(b) $P(T | F) = \\frac{P(T \\cap F)}{P(F)} = \\frac{5/30}{18/30} = \\frac{5}{18}$<br><br><b>Exam Tip:</b> With Venn diagrams, fill in the intersection FIRST, then work outwards.","content_zh":"<b>经典例题</b> [4 分]<br>30 人中 18 人踢足球，12 人打网球，5 人两项都玩。<br><br>(a) $P(F \\cup T) = \\frac{25}{30} = \\frac{5}{6}$<br>(b) $P(T|F) = \\frac{5}{18}$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.1', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Qualitative data</b>: non-numerical (colour, type). <b>Quantitative data</b>: numerical.<br>• <b>Discrete</b>: counted, specific values (number of siblings). <b>Continuous</b>: measured, any value in a range (height).<br>• <b>Frequency table</b>: tally marks → frequency column.<br>• <b>Grouped frequency table</b>: data sorted into class intervals. Use $\\leq$ or $<$ for boundaries.<br>• <b>Two-way table</b>: organises data by two categories.<br><br><b>Key Skills</b><br>• Choose appropriate class intervals (equal width, no gaps, no overlaps).<br>• Read and construct two-way tables.<br>• Find totals and missing values in frequency tables.","content_zh":"<b>知识回顾</b><br>• <b>定性数据</b>：非数值。<b>定量数据</b>：数值。<br>• <b>离散</b>：计数。<b>连续</b>：测量，范围内任意值。<br>• 频率表：画正字 → 频率列。分组频率表：等宽分组，无间隙无重叠。<br>• 双向表：按两个类别整理数据。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.1', 'examples', '{"content":"<b>Worked Example</b> [2 marks]<br>Classify each as discrete or continuous: (a) Number of pets, (b) Temperature, (c) Shoe size, (d) Time taken.<br><br><b>Solution:</b><br>(a) Discrete (counted)<br>(b) Continuous (measured)<br>(c) Discrete (specific values: 5, 5.5, 6, ...)<br>(d) Continuous (measured)<br><br><b>Exam Tip:</b> Shoe sizes look continuous but are actually discrete — only certain values exist.","content_zh":"<b>经典例题</b> [2 分]<br>分类：(a) 宠物数 (b) 温度 (c) 鞋码 (d) 所用时间。<br><br><b>解答：</b>(a) 离散 (b) 连续 (c) 离散 (d) 连续"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.2', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Bar charts</b>: compare frequencies of categories. Gaps between bars.<br>• <b>Pie charts</b>: angle $= \\frac{\\text{frequency}}{\\text{total}} \\times 360°$. Show proportion, not frequency.<br>• <b>Pictograms</b>: symbols represent data. Key shows how many each symbol means.<br>• <b>Line graphs</b>: show trends over time. Join points with straight lines.<br><br><b>Key Skills</b><br>• Read values from charts and graphs.<br>• Compare data shown in different formats.<br>• Critique misleading graphs (broken scales, unequal intervals, etc.).<br><br><b>Exam Tip</b><br>When reading pie charts, find the total first. Then angle ÷ 360 × total = frequency.","content_zh":"<b>知识回顾</b><br>• 柱状图：比较频率，柱间有间隙。饼图：角度 = $\\frac{频率}{总数} \\times 360°$。<br>• 象形图：符号代表数据，须有图例。折线图：时间趋势。<br><br><b>考试技巧</b><br>读饼图先找总数，再用角度计算频率。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.2', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>A pie chart represents 120 students. The \"Maths\" sector has angle $90°$. How many students chose Maths? If 30 students chose Science, find the angle for Science.<br><br><b>Solution:</b><br>Maths: $\\frac{90}{360} \\times 120 = 30$ students.<br>Science: $\\frac{30}{120} \\times 360° = 90°$","content_zh":"<b>经典例题</b> [3 分]<br>饼图代表 120 名学生，\"数学\"扇形角 $90°$。多少人选数学？30 人选科学，求角度。<br><br><b>解答：</b>数学 $= \\frac{90}{360} \\times 120 = 30$ 人。科学角度 $= \\frac{30}{120} \\times 360° = 90°$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.3', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Mean</b> $= \\frac{\\sum x}{n}$. For frequency table: $\\bar{x} = \\frac{\\sum fx}{\\sum f}$.<br>• <b>Median</b>: middle value of ordered data. Position $= \\frac{n+1}{2}$. For grouped data, use interpolation or cumulative frequency.<br>• <b>Mode</b>: most frequent value. <b>Modal class</b>: class with highest frequency.<br>• <b>Range</b> $=$ max $-$ min.<br><br><b>Extended Only</b><br>• For grouped data, mean uses <b>midpoints</b> and gives an <b>estimate</b>.<br>• <b>Interquartile range</b> $= Q_3 - Q_1$. Less affected by outliers than range.<br><br><b>Exam Tip</b><br>The mean is affected by extreme values (outliers). The median is more robust.","content_zh":"<b>知识回顾</b><br>• 平均值 $= \\frac{\\sum x}{n}$。频率表：$\\bar{x} = \\frac{\\sum fx}{\\sum f}$。<br>• 中位数：有序数据中间值。众数：频率最高。<br>• 极差 = 最大 - 最小。<br>• Extended：分组数据用组中值估算平均值。IQR $= Q_3 - Q_1$。<br><br><b>考试技巧</b>均值受极端值影响，中位数更稳健。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.3', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>Grouped frequency table:<br>| Score | 0-9 | 10-19 | 20-29 | 30-39 |<br>| Freq  | 3   | 8     | 12    | 7     |<br>Estimate the mean.<br><br><b>Solution:</b><br>Midpoints: 4.5, 14.5, 24.5, 34.5<br>$\\sum fx = 3(4.5) + 8(14.5) + 12(24.5) + 7(34.5)$<br>$= 13.5 + 116 + 294 + 241.5 = 665$<br>$\\sum f = 30$<br>Estimated mean $= \\frac{665}{30} = 22.2$","content_zh":"<b>经典例题</b> [4 分]<br>分组频率表（组中值 4.5, 14.5, 24.5, 34.5；频率 3, 8, 12, 7）。估算平均值。<br><br><b>解答：</b>$\\frac{13.5 + 116 + 294 + 241.5}{30} = \\frac{665}{30} = 22.2$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.4', 'knowledge', '{"content":"<b>Recap</b><br>• <b>Stem-and-leaf diagram</b>: organises raw data. Must be ordered with a key. E.g. $3 | 2$ means 32.<br>• <b>Back-to-back</b> stem-and-leaf: compares two data sets on the same stem.<br>• <b>Frequency polygon</b>: plot midpoints of class intervals, join with straight lines.<br>• Can read median, quartiles, and range from an ordered stem-and-leaf diagram.<br><br><b>Key Skills</b><br>• Construct an ordered stem-and-leaf diagram.<br>• Find the median from a stem-and-leaf diagram.<br>• Draw and interpret frequency polygons.<br><br><b>Exam Tip</b><br>Remember: stems go on the left, leaves on the right, and leaves must be in order.","content_zh":"<b>知识回顾</b><br>• <b>茎叶图</b>：有序排列原始数据，必须有图例。如 $3|2$ 表示 32。<br>• 背靠背茎叶图：比较两组数据。<br>• 频率折线图：用组中值画点连线。<br><br><b>考试技巧</b>茎在左，叶在右，叶必须有序排列。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.4', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>Data: 23, 31, 18, 27, 35, 22, 29, 31, 24, 38, 19, 26. Draw a stem-and-leaf diagram and find the median.<br><br><b>Solution:</b><br>Key: $1|8$ means 18<br>$1 \\;|\\; 8 \\; 9$<br>$2 \\;|\\; 2 \\; 3 \\; 4 \\; 6 \\; 7 \\; 9$<br>$3 \\;|\\; 1 \\; 1 \\; 5 \\; 8$<br><br>12 values → median = average of 6th and 7th: $\\frac{26 + 27}{2} = 26.5$","content_zh":"<b>经典例题</b> [3 分]<br>数据 12 个值，画茎叶图求中位数。<br><br><b>解答：</b>第 6 个和第 7 个的平均：$\\frac{26 + 27}{2} = 26.5$"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.5', 'knowledge', '{"content":"<b>Recap</b><br>• A <b>scatter diagram</b> shows the relationship between two variables.<br>• <b>Positive correlation</b>: as one increases, the other increases (points go up-right).<br>• <b>Negative correlation</b>: as one increases, the other decreases (points go down-right).<br>• <b>No correlation</b>: no clear pattern.<br>• <b>Line of best fit</b>: straight line through the data that best represents the trend. Should pass near the <b>mean point</b> $(\\bar{x}, \\bar{y})$.<br><br><b>Key Skills</b><br>• Plot scatter diagrams and draw a line of best fit by eye.<br>• Describe the type and strength of correlation.<br>• Use the line of best fit to make predictions (interpolation is more reliable than extrapolation).<br><br><b>Watch Out!</b><br>Correlation does NOT mean causation. Two correlated variables may both be caused by a third factor.","content_zh":"<b>知识回顾</b><br>• 散点图显示两变量关系。<br>• 正相关：同增。负相关：一增一减。无相关：无规律。<br>• 最佳拟合线：过均值点 $(\\bar{x}, \\bar{y})$ 附近。<br>• 内插比外推更可靠。<br><br><b>注意！</b>相关性 ≠ 因果关系。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.5', 'examples', '{"content":"<b>Worked Example</b> [3 marks]<br>A student plots temperature against ice cream sales. The points show a clear upward trend. (a) Describe the correlation. (b) Estimate sales at 25°C if the line of best fit passes through $(20, 150)$ and $(30, 250)$.<br><br><b>Solution:</b><br>(a) <b>Strong positive correlation</b>: as temperature increases, sales increase.<br>(b) Gradient $= \\frac{250-150}{30-20} = 10$ sales per °C.<br>At 25°C: $150 + 5 \\times 10 = 200$ sales.<br><br><b>Exam Tip:</b> State correlation type AND direction. \"Positive\" alone is not enough — say \"positive correlation\".","content_zh":"<b>经典例题</b> [3 分]<br>温度 vs 冰淇淋销量散点图呈上升趋势。<br><br>(a) <b>强正相关</b>：温度升高，销量增加。<br>(b) 斜率 $= 10$，25°C 时 $= 200$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.6', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• <b>Cumulative frequency</b> = running total of frequencies.<br>• Plot cumulative frequency at the <b>upper class boundary</b> of each class.<br>• The curve is always S-shaped (increasing, never decreases).<br><br><b>Reading from the curve</b><br>• Median: read at $\\frac{n}{2}$.<br>• Lower quartile ($Q_1$): at $\\frac{n}{4}$. Upper quartile ($Q_3$): at $\\frac{3n}{4}$.<br>• IQR $= Q_3 - Q_1$.<br>• Percentiles: e.g. 10th percentile at $\\frac{10}{100} \\times n$.<br><br><b>Box-and-whisker plot</b><br>• Shows: minimum, $Q_1$, median, $Q_3$, maximum.<br>• Useful for comparing distributions side by side.<br><br><b>Exam Tip</b><br>Plot points at the upper boundary, not the midpoint. Join with a smooth S-curve, not straight lines.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• 累积频率 = 频率累加。画在每组的<b>上界</b>处。曲线呈 S 形。<br>• 中位数在 $\\frac{n}{2}$。$Q_1$ 在 $\\frac{n}{4}$，$Q_3$ 在 $\\frac{3n}{4}$。IQR $= Q_3 - Q_1$。<br><br><b>箱线图</b>：最小值, $Q_1$, 中位数, $Q_3$, 最大值。<br><br><b>考试技巧</b>画在上界处，用光滑 S 曲线连接。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.6', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>From a cumulative frequency graph with $n = 60$:<br>(a) Find the median, $Q_1$, $Q_3$, and IQR.<br>(b) How many scored more than 70?<br><br><b>Solution:</b><br>(a) Median at $\\frac{60}{2} = 30$th → read across: median $= 55$<br>$Q_1$ at 15th $= 42$. $Q_3$ at 45th $= 68$.<br>IQR $= 68 - 42 = 26$<br><br>(b) CF at 70 $= 48$. More than 70 $= 60 - 48 = 12$ students.","content_zh":"<b>经典例题</b> [4 分]<br>累积频率图 $n = 60$。求中位数、$Q_1$、$Q_3$、IQR 和 70 分以上人数。<br><br><b>解答：</b>中位数 55，$Q_1 = 42$，$Q_3 = 68$，IQR $= 26$。70 分以上 $= 60 - 48 = 12$ 人。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.7', 'knowledge', '{"content":"<b>Extended Only</b><br><br><b>Recap</b><br>• A <b>histogram</b> displays continuous grouped data. <b>No gaps</b> between bars.<br>• The vertical axis is <b>frequency density</b>, NOT frequency.<br>• $\\text{Frequency density} = \\frac{\\text{frequency}}{\\text{class width}}$.<br>• The <b>area</b> of each bar = frequency (height × width).<br><br><b>Key Skills</b><br>• Draw a histogram from a grouped frequency table with <b>unequal</b> class widths.<br>• Read frequencies from a histogram: frequency $=$ area of bar $=$ frequency density $\\times$ width.<br>• Estimate the mean or median class from a histogram.<br><br><b>Watch Out!</b><br>Bar charts have equal widths and use frequency. Histograms may have unequal widths and use frequency density.","content_zh":"<b>仅 Extended</b><br><br><b>知识回顾</b><br>• 直方图：连续分组数据，柱间无间隙。<br>• 纵轴是<b>频率密度</b>，不是频率。频率密度 $= \\frac{频率}{组距}$。<br>• 每根柱的<b>面积</b> = 频率。<br><br><b>注意！</b>柱状图用频率（等宽），直方图用频率密度（可不等宽）。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
INSERT INTO section_edits (board, section_id, module, data) VALUES ('cie', '9.7', 'examples', '{"content":"<b>Worked Example</b> [4 marks]<br>A histogram shows a bar for $20 \\leq t < 35$ with frequency density 2.4. Find the frequency for this class. Another class $35 \\leq t < 40$ has frequency 15. Find its frequency density.<br><br><b>Solution:</b><br>Class $20 \\leq t < 35$: width $= 15$.<br>Frequency $= 2.4 \\times 15 = 36$.<br><br>Class $35 \\leq t < 40$: width $= 5$.<br>Frequency density $= \\frac{15}{5} = 3$.<br><br><b>Exam Tip:</b> Always check: frequency = density × width. If you are given the area, divide by width to get density.","content_zh":"<b>经典例题</b> [4 分]<br>直方图中 $20 \\leq t < 35$ 频率密度 2.4，求频率。$35 \\leq t < 40$ 频率 15，求密度。<br><br><b>解答：</b>频率 $= 2.4 \\times 15 = 36$。密度 $= \\frac{15}{5} = 3$。"}'::jsonb) ON CONFLICT (board, section_id, module) DO UPDATE SET data = EXCLUDED.data, updated_at = now();
